contracts/PrecogMarketV7.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity 0.7.6;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import "./ABDKMath64x64.sol";

/**
 * @title PrecogMarketV7: An implementation for liquidity-sensitive LMSR market maker in Solidity
 * @author Marto (https://github.com/0xMarto)
 * @dev Feel free to make any adjustments to the code (DMs are open @0xMarto)
 */
contract PrecogMarketV7 {
    using SafeERC20 for IERC20;
    using SafeMath for uint256;

    struct SharesInfo {
        uint256 buys;  // Total amount of Buys
        uint256 sells;  // Total amount of Sells
        uint256 deposited; // Total collateral-in on Buys
        uint256 withdrew; // Total collateral-Out on Sells
        uint256 redeemed; // Total collateral-Out on Redeems
        mapping(uint256 => uint256) balances;  // Shares balances by outcome (has an custom getter)
    }

    // Public variables
    address public owner;  // Should be the PrecogMaster contract
    address public token;  // Collateral to Buy and redeem shares
    uint256 public id;  // Unique Identifier for the market
    uint256 public totalOutcomes; // Amount of outcomes (2 usually mean 1=YES, 2=NO)
    address public oracle;  // EOA or Contract in change to reportResults
    uint256 public startTimestamp;  // Time when Buy/Sell shares are enabled
    uint256 public endTimestamp;  // Time when Buy/Sell shares are disabled
    uint256 public closeTimestamp;  // Time when results were reported
    uint256 public result;  // Final outcome of the market (published by the oracle)
    mapping(address => SharesInfo) public accountShares;  // Account shares balances and info

    // Private variables
    int128[] private shares;  // Amount of shares indexed by outcome (signed 64.64 bit fixed point number)
    int128 private beta;  // LMSR market liquidity variable (signed 64.64 bit fixed point number)
    int128 private alpha;  // Liquidity-Sensitive LMSR market variable (signed 64.64 bit fixed point number)
    int128 private dust;  // Token leak mitigation variable used in share sells (signed 64.64 bit fixed point number)
    int128 private currentCost;  // Current amount of liquidity in the market (signed 64.64 bit fixed point number)
    int128 private totalShares;  // Total amount of shares of all outcomes (signed 64.64 bit fixed point number)
    uint256 private totalBuys;  // Total amount of buys made from all account
    uint256 private totalSells;  // Total amount of sells made from all account
    bool private marketSetup;  // Flag that indicates that a market was configured correctly
    bool private internalCall;  // Flag that indicates that the current call is internal

    // Events emitted
    event SharesBought(address indexed account, uint256 indexed outcome, uint256 amount, uint256 tokenIn);
    event SharesSold(address indexed account, uint256 indexed outcome, uint256 amount, uint256 tokenOut);
    event SharesRedeemed(address indexed account, uint256 indexed outcome, uint256 amount, uint256 tokenOut);
    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);

    // Modifiers
    modifier onlyAfterSetup {
        require(marketSetup == true, "Not setup");
        _;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner");
        _;
    }

    modifier onlyOwnerOrInternal() {
        require(msg.sender == owner || internalCall, "Only owner or self");
        _;
        internalCall = false;
    }

    modifier onlyOracle() {
        require(msg.sender == oracle, "Only oracle");
        _;
    }

    /**
     * @notice Constructor like function for the market maker
     * @param _token ERC-20 token will be used to purchase and redeem rewards for this Market
     */
    function initialize(address _token) public {
        require(owner == address(0) && token == address(0), "Already initialized");
        owner = msg.sender;
        token = _token;
    }

    /**
     * @notice Sets up the market with the specified parameters
     * @param _id The unique identifier for the market
     * @param _oracle The address of the oracle that will report results
     * @param _totalOutcomes The number of possible outcomes for the market
     * @param _subsidy The initial funding used to seed the market (defined on initialized token)
     * @param _overround The AMM profit margin in basis points (bps) [recommended: (100 * _totalOutcomes)]
     */
    function setup(uint _id, address _oracle, uint _totalOutcomes, uint _subsidy, uint _overround) public onlyOwner {
        require(!marketSetup, "Already setup");
        require(_overround > 0, "Unsupported overround");
        require(_totalOutcomes > 0, "Unsupported outcomes");

        // Get initial funding tokens from sender
        IERC20(token).safeTransferFrom(msg.sender, address(this), _subsidy);

        // Save basic parameters
        id = _id;
        oracle = _oracle;
        totalOutcomes = _totalOutcomes;

        // Calculate initialization variables
        int128 initialSubsidy = getTokenEth(token, _subsidy);
        int128 n = ABDKMath.fromUInt(_totalOutcomes);
        int128 overround = ABDKMath.divu(_overround, 10_000); // if the overround is too low the exp function overflows
        alpha = ABDKMath.div(overround, ABDKMath.mul(n, ABDKMath.ln(n)));
        beta = ABDKMath.mul(ABDKMath.mul(initialSubsidy, n), alpha);
        shares = new int128[](totalOutcomes.add(1));
        for (uint256 outcome = 1; outcome <= totalOutcomes; outcome++) {
            shares[outcome] = initialSubsidy;
            totalShares = ABDKMath.add(totalShares, initialSubsidy);
        }

        // Initialize token leak mitigation of 0.001% (could be a setup parameter in the future)
        // Note: Needed to avoid leaks due to rounding errors on math logarithmic and exponential approximations
        dust = ABDKMath.fromUInt(100_000);  // 100k as signed 64.64 bit fixed point

        // Register successful initialization
        marketSetup = true;

        // Optimization: pre calculate current cost to avoid extra calculation on buys and sells
        currentCost = cost();
    }

    /**
     * @notice Buys outcome shares for the specified outcome
     * @param _outcome The outcome of which shares are being bought (e.g.: 1 for YES, 2 for NO)
     * @param _amount The number of outcome shares to buy (as a signed 64.64-bit fixed point number)
     * @return tokenCost The total token amount used for buying the specified amount of outcome shares
     */
    function buy(uint256 _outcome, int128 _amount) public onlyAfterSetup returns (uint256 tokenCost) {
        // Send BUY call to internal function with msg sender
        internalCall = true;
        return _buy(_outcome, _amount, msg.sender);
    }

    /**
     * @notice Allows buying market shares for a specified account (limited to only Self or Owner)
     * @param _outcome The outcome of which shares are being bought (e.g.: 1 for YES, 2 for NO)
     * @param _amount The number of outcome shares to buy (as a signed 64.64-bit fixed point number)
     * @param _account The address of the buyer
     * @return tokenCost The total token amount used for buying the specified amount of outcome shares
     */
    function _buy(uint256 _outcome, int128 _amount, address _account) public onlyOwnerOrInternal
    returns (uint256 tokenCost) {
        require(_outcome > 0 && _outcome <= totalOutcomes, "Invalid outcome");
        require(_amount > 0, "Invalid amount");
        require(block.timestamp >= startTimestamp, "Market not started");
        require(endTimestamp == 0 || block.timestamp <= endTimestamp, "Market already ended");
        require(closeTimestamp == 0, "Market already closed");

        // Add amount of shares to be bought from individual and total shares counters
        shares[_outcome] = ABDKMath.add(shares[_outcome], _amount);
        totalShares = ABDKMath.add(totalShares, _amount);

        // Calculate new BETA parameter (taking into account new total shares and fixed alpha)
        beta = ABDKMath.mul(totalShares, alpha);

        // Calculate new current cost and price to pay. After that, update current cost variable
        int128 sumTotal;
        for (uint outcome = 1; outcome <= totalOutcomes; outcome++) {
            sumTotal = ABDKMath.add(sumTotal, ABDKMath.exp(ABDKMath.div(shares[outcome], beta)));
        }
        int128 newCost = ABDKMath.mul(beta, ABDKMath.ln(sumTotal));
        int128 deltaCost = ABDKMath.sub(newCost, currentCost);
        currentCost = newCost;

        // Get amount of tokens from sender (as current payment)
        tokenCost = getTokenWei(token, deltaCost);
        require(tokenCost > 0, "Invalid cost");
        IERC20(token).safeTransferFrom(msg.sender, address(this), tokenCost);
        uint outcomeShares = getTokenWei(token, _amount);

        // Register BUY in market total and Account details
        totalBuys = totalBuys.add(1);
        accountShares[_account].buys = accountShares[_account].buys.add(1);
        accountShares[_account].deposited = accountShares[_account].deposited.add(tokenCost);
        accountShares[_account].balances[_outcome] = accountShares[_account].balances[_outcome].add(outcomeShares);

        emit SharesBought(_account, _outcome, outcomeShares, tokenCost);
        return tokenCost;
    }

    /**
     * @notice Sells outcome shares for the specified outcome
     * @param _outcome The outcome of which shares are being sold (e.g.: 1 for YES, 2 for NO)
     * @param _amount The number of outcome shares to sell (as a signed 64.64-bit fixed point number)
     * @return tokenReturn The total amount of tokens received from selling the outcome shares
     */
    function sell(uint256 _outcome, int128 _amount) public onlyAfterSetup returns (uint256 tokenReturn) {
        // Send SELL call to internal function
        internalCall = true;
        return _sell(_outcome, _amount, msg.sender);
    }

    /**
     * @notice Allows selling market shares from a specified account (limited to only Self or Owner)
     * @param _outcome The outcome for which shares are being sold (e.g.: 1 for YES, 2 for NO)
     * @param _amount The number of outcome shares to sell (as a signed 64.64-bit fixed point number)
     * @param _account The address of the seller
     * @return tokenReturn The total amount of tokens received from selling the outcome shares
     */
    function _sell(uint256 _outcome, int128 _amount, address _account) public onlyOwnerOrInternal
    returns (uint256 tokenReturn) {
        require(_outcome > 0 && _outcome <= totalOutcomes, "Invalid outcome");
        require(_amount > 0, "Invalid amount");
        require(block.timestamp >= startTimestamp, "Market not started");
        require(endTimestamp == 0 || block.timestamp <= endTimestamp, "Market already ended");
        require(closeTimestamp == 0, "Market already closed");

        // Remove amount of shares to be sold from individual and total shares counters
        shares[_outcome] = ABDKMath.sub(shares[_outcome], _amount);
        totalShares = ABDKMath.sub(totalShares, _amount);

        // Calculate new BETA parameter (taking into account new total shares and fixed alpha)
        beta = ABDKMath.mul(totalShares, alpha);

        // Calculate new cost and tokens to return. After that, update current cost variable
        int128 sumTotal;
        for (uint outcome = 1; outcome <= totalOutcomes; outcome++) {
            sumTotal = ABDKMath.add(sumTotal, ABDKMath.exp(ABDKMath.div(shares[outcome], beta)));
        }
        int128 newCost = ABDKMath.mul(beta, ABDKMath.ln(sumTotal));
        int128 deltaCost = ABDKMath.sub(currentCost, newCost);
        int128 deltaDust = ABDKMath.div(deltaCost, dust);  // Token leak mitigation
        currentCost = newCost;

        // Calculate return amount of token to send
        tokenReturn = getTokenWei(token, ABDKMath.sub(deltaCost, deltaDust));

        require(tokenReturn > 0, "Invalid return");
        uint outcomeShares = getTokenWei(token, _amount);

        // Check that the received account have the amount of shares to sell
        require(accountShares[_account].balances[_outcome] >= outcomeShares, "Insufficient balance");

        // Register SELL in market total and Account details
        totalSells = totalSells.add(1);
        accountShares[_account].sells = accountShares[_account].sells.add(1);
        accountShares[_account].withdrew = accountShares[_account].withdrew.add(tokenReturn);
        accountShares[_account].balances[_outcome] = accountShares[_account].balances[_outcome].sub(outcomeShares);

        // Transfer collateral tokens to received account
        IERC20(token).safeTransfer(_account, tokenReturn);

        emit SharesSold(_account, _outcome, outcomeShares, tokenReturn);
        return tokenReturn;
    }

    /**
     * @notice Updates the start and end timestamps for the market (limited to only owner)
     * @param _startTimestamp The timestamp when the market starts allowing trading
     * @param _endTimestamp The timestamp when the market stops allowing trading
     */
    function updateDates(uint256 _startTimestamp, uint256 _endTimestamp) public onlyOwner {
        startTimestamp = _startTimestamp;
        endTimestamp = _endTimestamp;
    }

    /**
     * @notice Update the oracle address of the market (limited to only owner)
     * @param _newOracle The address of the EOA or contract that can close the market
     */
    function updateOracle(address _newOracle) public onlyOwner {
        require(_newOracle != address(0), "Invalid new oracle");
        oracle = _newOracle;
    }

    /**
     * @notice Reports the result of the market (limited to only Oracle)
     * @param _id The unique identifier of the market
     * @param _outcome The outcome that is reported as the result of the market
     */
    function reportResult(uint256 _id, uint256 _outcome) public onlyOracle {
        // Validate received inputs
        require(_id == id, "Invalid market");
        require(_outcome > 0 && _outcome <= totalOutcomes, "Invalid outcome");

        // Check current state of the market
        require(block.timestamp > endTimestamp, "Market not ended");
        require(closeTimestamp == 0, "Market already closed");

        // Register reported results and register current time
        result = _outcome;
        closeTimestamp = block.timestamp;
    }

    /**
     * @notice Redeems the current sender shares for the result of the market
     * @return redeemedShares The number of shares redeemed
     */
    function redeemShares() public onlyAfterSetup returns (uint256 redeemedShares) {
        internalCall = true;
        return _redeem(msg.sender);
    }

    /**
     * @notice Redeems shares in batch for multiple accounts  (limited to only Oracle)
     * @param _accounts The list of accounts to redeem shares for
     * @dev The list of accounts could be calculated using the "SharesBought" event
     * @return redeems The number of successful redeems
     */
    function redeemBatch(address[] memory _accounts) public onlyAfterSetup onlyOracle returns (uint256 redeems) {
        for (uint256 i = 0; i < _accounts.length; i++) {
            internalCall = true;
            try this._redeem(_accounts[i]) {
                redeems.add(1);
            } catch {
                // CASE: `_redeem` call reverted (expected if the account don't have redeemable shares)
                internalCall = false; // Disable internal just incase of revert
            }
        }
        return redeems;
    }

    /**
     * @notice Redeems the received account shares for the result of the market (limited to only Self or Owner)
     * @param _account The address of the account with shares of the market
     * @return redeemedShares The number of shares redeemed
     */
    function _redeem(address _account) public onlyOwnerOrInternal returns (uint256 redeemedShares) {
        // Check current state of the market and received account
        require(closeTimestamp > 0, "Market not closed");
        require(accountShares[_account].redeemed == 0, "Shares already redeemed");

        // Get amount of shares to be redeemed for received account
        redeemedShares = accountShares[_account].balances[result];
        require(redeemedShares > 0, "Nothing to redeem");

        // Register amount of shares redeemed and send corresponding collateral tokens (ratio 1:1)
        accountShares[_account].redeemed = redeemedShares;
        IERC20(token).safeTransfer(_account, redeemedShares);

        emit SharesRedeemed(_account, result, redeemedShares, redeemedShares);
        return redeemedShares;
    }

    /**
     * @notice Withdraws any remaining liquidity from the market (limited to only owner)
     * @param _token The address of the ERC-20 token to withdraw
     */
    function withdraw(address _token) public onlyAfterSetup onlyOwner {
        require(closeTimestamp > 0, "Market not closed");
        IERC20(_token).safeTransfer(msg.sender, IERC20(_token).balanceOf(address(this)));
    }

    /**
     * @notice Transfers the ownership of the contract to a new owner (limited to only current owner)
     * @param _newOwner The address of the new owner
     */
    function transferOwnership(address _newOwner) public virtual onlyOwner {
        require(_newOwner != address(0), "Invalid new owner");
        emit OwnershipTransferred(owner, _newOwner);
        owner = _newOwner;
    }

    /**
     * @notice Gets the total collateral spent in the market
     * @return totalCost The total cost in the form of a signed 64.64-bit fixed point number
     */
    function cost() public view onlyAfterSetup returns (int128 totalCost) {
        int128 sumTotal;
        for (uint outcome = 1; outcome <= totalOutcomes; outcome++) {
            sumTotal = ABDKMath.add(sumTotal, ABDKMath.exp(ABDKMath.div(shares[outcome], beta)));
        }
        return ABDKMath.mul(beta, ABDKMath.ln(sumTotal));
    }

    /**
     * @notice Gets the cost of buying the specified amount of outcome shares
     * @param _outcome The outcome for which shares are being bought
     * @param _amount The number of outcome shares to buy (as signed 64.64-bit fixed point number)
     * @return tokenCost The token cost amount (as a signed 64.64-bit fixed point number)
     */
    function buyPrice(uint256 _outcome, int128 _amount) public view returns (int128 tokenCost) {
        return ABDKMath.sub(costAfterBuy(_outcome, _amount), currentCost);
    }

    /**
     * @notice Gets the return from selling the specified amount of outcome shares
     * @param _outcome The outcome for which shares are being sold
     * @param _amount The number of outcome shares to sell (as signed 64.64-bit fixed point number)
     * @return tokenReturn The token return amount (as a signed 64.64-bit fixed point number)
     */
    function sellPrice(uint256 _outcome, int128 _amount) public view returns (int128 tokenReturn) {
        int128 deltaCost = ABDKMath.sub(currentCost, costAfterSell(_outcome, _amount));
        int128 deltaDust = ABDKMath.div(deltaCost, dust);  // token leak mitigation
        return ABDKMath.sub(deltaCost, deltaDust);
    }

    /**
     * @notice Gets the current market state information
     * @return totalShares The current total shares minted for all outcomes of the market
     * @return sharesBalances All shares balances (indexed by outcome)
     * @return currentCost The current liquidity of the market
     * @return totalBuys Buys counter of the market
     * @return totalSells Sells counter of the market
     */
    function getMarketInfo() public view returns (int128, int128[] memory, int128, uint256, uint256) {
        int128[] memory sharesBalances = new int128[](totalOutcomes.add(1));

        if (!marketSetup) {
            return (0, sharesBalances, 0, 0, 0);
        }

        // Populate shares balances based on total outcomes configured for this market
        for (uint256 outcome = 1; outcome <= totalOutcomes; outcome++) {
            sharesBalances[outcome] = shares[outcome];
        }

        return (totalShares, sharesBalances, currentCost, totalBuys, totalSells);
    }

    /**
     * @notice Gets current market buy and sell prices for all outcomes
     * @dev Helper function to fast calculate market prediction and spreads
     * @return buyPrices buy price of 1 share for all outcomes (indexed by outcome)
     * @return sellPrices sell price of 1 share for all outcomes (indexed by outcome)
     */
    function getPrices() public view returns (uint256[] memory buyPrices, uint256[] memory sellPrices) {
        buyPrices = new uint256[](totalOutcomes.add(1));
        sellPrices = new uint256[](totalOutcomes.add(1));
        for (uint256 outcome = 1; outcome <= totalOutcomes; outcome++) {
            int128 oneShare = 18446744073709551616;  // 1 share as int128 (signed 64.64 bit fixed point number)
            buyPrices[outcome] = getTokenWei(token, buyPrice(outcome, oneShare));
            sellPrices[outcome] = getTokenWei(token, sellPrice(outcome, oneShare));
        }
        return (buyPrices, sellPrices);
    }

    /**
     * @notice Gets the amount of shares that an account owns for all outcomes
     * @param _account The address of the account with shares of the market
     * @return balances The balances of shares for all outcomes (indexed by outcome)
     */
    function getAccountOutcomeBalances(address _account) public view returns (uint256[] memory balances) {
        balances = new uint256[](totalOutcomes.add(1));
        for (uint256 outcome = 1; outcome <= totalOutcomes; outcome++) {
            balances[outcome] = accountShares[_account].balances[outcome];
        }
        return balances;
    }

    /**
     *  @notice Gets the total collateral spent in the market after a received BUY trade
     *  @dev Internal function used to calculate buy price
     */
    function costAfterBuy(uint256 _outcome, int128 _amount) internal view returns (int128) {
        int128 newSumTotal;
        int128[] memory newShares = new int128[](shares.length);
        int128 newTotalShares = totalShares;

        // Add new amount of shares to received outcome
        for (uint256 outcome = 1; outcome <= totalOutcomes; outcome++) {
            if (outcome == _outcome) {
                newShares[outcome] = ABDKMath.add(shares[outcome], _amount);
                newTotalShares = ABDKMath.add(newTotalShares, _amount);
            } else {
                newShares[outcome] = shares[outcome];
            }
        }

        // Calculate new cost based on newTotalShares and newQ values
        int128 newBeta = ABDKMath.mul(newTotalShares, alpha);
        for (uint256 outcome = 1; outcome <= totalOutcomes; outcome++) {
            newSumTotal = ABDKMath.add(newSumTotal, ABDKMath.exp(ABDKMath.div(newShares[outcome], newBeta)));
        }
        return ABDKMath.mul(newBeta, ABDKMath.ln(newSumTotal));
    }

    /**
     *  @notice Gets the total collateral spent in the market after a received SELL trade
     *  @dev Internal function used to calculate sell price
     */
    function costAfterSell(uint256 _outcome, int128 _amount) internal view returns (int128) {
        int128 newSumTotal;
        int128[] memory newShares = new int128[](shares.length);
        int128 newTotalShares = totalShares;

        // Add new amount of shares to received outcome
        for (uint256 outcome = 1; outcome <= totalOutcomes; outcome++) {
            if (outcome == _outcome) {
                newShares[outcome] = ABDKMath.sub(shares[outcome], _amount);
                newTotalShares = ABDKMath.sub(newTotalShares, _amount);
            } else {
                newShares[outcome] = shares[outcome];
            }
        }

        // Calculate new cost based on newTotalShares and newShares values
        int128 newBeta = ABDKMath.mul(newTotalShares, alpha);
        for (uint256 outcome = 1; outcome <= totalOutcomes; outcome++) {
            newSumTotal = ABDKMath.add(newSumTotal, ABDKMath.exp(ABDKMath.div(newShares[outcome], newBeta)));
        }
        return ABDKMath.mul(newBeta, ABDKMath.ln(newSumTotal));
    }

    /**
     *  @notice Translate int128 (signed 64.64 bit fixed point number) [in ether] to uint256 token amount [in wei]
     *  @dev Internal function used to transform encoded number values
     */
    function getTokenWei(address _token, int128 _amount) internal view returns (uint256) {
        uint256 decimals = ERC20(_token).decimals();
        return ABDKMath.mulu(_amount, 10 ** decimals);
    }

    /**
     *  @notice Translate uint256 token amount [in wei] to int128 (signed 64.64 bit fixed point number) [in ether]
     *  @dev Internal function used to transform encoded number values
     */
    function getTokenEth(address _token, uint256 _amount) internal view returns (int128) {
        uint256 decimals = ERC20(_token).decimals();
        return ABDKMath.divu(_amount, 10 ** decimals);
    }
}

contracts/PrecogMarketV8.sol.content:
// SPDX-License-Identifier: BUSL-1.1
pragma solidity 0.7.6;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import "@openzeppelin/contracts/math/SafeMath.sol";
import "./ABDKMath64x64.sol";

/**
 * @title PrecogMarketV8: An implementation for Liquidity-Sensitive LMSR market maker in Solidity
 * @author Marto (https://github.com/0xMarto)
 * @dev Feel free to leave any code improvements (DMs are open @0xMarto)
 */
contract PrecogMarketV8 {
    using SafeERC20 for IERC20;
    using SafeMath for uint256;

    int128 public constant ONE_SHARE = int128(1) << 64;  // Constant to ensure no fractional share buying

    struct AccountData {
        uint64 buys;  // Total amount of Buys
        uint64 sells;  // Total amount of Sells
        uint256 deposited; // Total collateral-in on Buys
        uint256 withdrawn; // Total collateral-out on Sells
        uint256 redeemed; // Total collateral-out on Redeems (equal to redeemed shares)
        mapping(uint256 => uint256) balances;  // Shares balances by outcome (has a custom getter)
    }

    // Public variables
    address public owner;  // Should be the PrecogMaster contract
    address public token;  // ERC20 collateral of the market (to buy, sell and redeem shares)
    address public oracle;  // EOA or Contract responsible to report market result
    uint32 public id;  // Unique Identifier for the market on the Precog Master contract
    uint16 public totalOutcomes; // Amount of outcomes (2 usually mean 1=YES, 2=NO)
    uint16 public result;  // Final outcome of the market (published by the oracle)
    uint64 public closeTimestamp;  // Time when the result was reported
    uint64 public startTimestamp;  // Time when Buy/Sell shares are enabled
    uint64 public endTimestamp;  // Time when Buy/Sell shares are disabled
    bool public datesUpdateEnabled;  // Flag that enables updates to market dates (signaled by the oracle)

    // Private variables
    mapping(address => AccountData) private accounts;  // Account shares balances & stats (has custom getter)
    int128[] private shares;  // Market shares balances indexed by outcome (signed 64.64 bit fixed point number)
    uint256 private tokenScale;  // Cached scale of the initialized token (10 ** tokenDecimals)
    uint256 private initialCollateral;  // Initial amount of collateral received on setup
    int128 private alpha;  // Liquidity-Sensitive LMSR market variable (signed 64.64 bit fixed point number)
    int128 private sellFeeFactor;  // Calculate sell fees and mitigate token leaks (signed 64.64 bit fixed point number)
    int128 private currentCost;  // Current amount of liquidity in the market (signed 64.64 bit fixed point number)
    int128 private totalShares;  // Total amount of shares across all outcomes (signed 64.64 bit fixed point number)
    int128 private totalRedeemedShares;  // Total shares already redeemed (signed 64.64 bit fixed point number)
    int128 private initialShares;  // Initial shares minted for each outcome (signed 64.64 bit fixed point number)
    uint64 private totalBuys;  // Total amount of buys made from all account
    uint64 private totalSells;  // Total amount of sells made from all account
    uint8 private unlocked;  // No reentrancy flag

    // Events emitted
    event SharesBought(address indexed account, uint256 indexed outcome, uint256 amount, uint256 tokenIn);
    event SharesSold(address indexed account, uint256 indexed outcome, uint256 amount, uint256 tokenOut);
    event SharesRedeemed(address indexed account, uint256 indexed outcome, uint256 amount, uint256 tokenOut);
    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);
    event ResultReported(address indexed oracle, uint256 indexed result, uint256 closeTimestamp);
    event DatesUpdated(address indexed updater, uint64 newStartTimestamp, uint64 newEndTimestamp);

    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner");
        _;
    }

    modifier onlyOracle() {
        require(msg.sender == oracle, "Only oracle");
        _;
    }

    modifier onlyOracleOrOwner() {
        require(msg.sender == oracle || msg.sender == owner, "Only oracle or owner");
        _;
    }

    modifier lock() {
        require(unlocked == 1, "Unavailable"); // reentrancy check
        unlocked = 2;   // Activate lock! (enter critical section)
        _;
        unlocked = 1;   // Deactivate lock! (exit critical section)
    }

    /**
     * @notice Constructor like function for the market maker
     * @param _token ERC-20 token will be used to purchase and redeem rewards for the market
     */
    function initialize(address _token) external {
        require(owner == address(0) && token == address(0), "Already initialized");
        owner = msg.sender;
        token = _token;

        // Optimization: Pre fetch decimals to avoid extra calls on market trades
        uint8 decimals = ERC20(_token).decimals();
        require(decimals <= 18, "Invalid decimals");
        tokenScale = 10 ** decimals;
    }

    /**
     * @notice Sets up the market with the specified parameters
     * @param _id The unique identifier for the market
     * @param _oracle The address of the oracle that will report the result
     * @param _outcomes The number of possible outcomes for the market
     * @param _liquidity The initial funding used to seed the market (defined on initialized token)
     * @param _overround The AMM profit margin in basis points (bps) [recommended: (100 * _totalOutcomes)]
     */
    function setup(
        uint256 _id, address _oracle, uint256 _outcomes, uint256 _liquidity, uint256 _overround
    ) external onlyOwner {
        require(unlocked == 0, "Already setup");  // `unlock` it's only initialized at `_setup`
        require(_outcomes >= 2, "Invalid outcomes");  // Min 2 possible outcomes
        require(_liquidity >= tokenScale, "Invalid liquidity");  // Min 1 collateral unit (based on decimals)
        require(_overround >= 200, "Invalid overround");  // Min 2% overround (based on sensitivity)

        // Get initial liquidity tokens from sender
        IERC20(token).safeTransferFrom(msg.sender, address(this), _liquidity);

        // Call internal function to setup the market
        _setup(_id, _oracle, _outcomes, _liquidity, _overround);

        // Save initial collateral received by the market
        initialCollateral = _liquidity;
    }

    /**
     * @notice Sets up the market with the Virtual Liquidity received and specified parameters
     * @param _id The unique identifier for the market
     * @param _oracle The address of the oracle that will report the result
     * @param _outcomes Total number of possible outcomes for the market
     * @param _liquidity Initial virtual liquidity used to seed the market (defined on initialized token)
     * @param _overround The AMM profit margin in basis points (bps) [recommended: (100 * _totalOutcomes)]
     * @param _funding liquidity used to collateralize the market (should be higher than max theoretical loss)
     */
    function setupVL(
        uint256 _id, address _oracle, uint256 _outcomes, uint256 _liquidity, uint256 _overround, uint256 _funding
    ) external onlyOwner {
        require(unlocked == 0, "Already setup");  // `unlock` it's only initialized at `_setup`
        require(_outcomes >= 2, "Invalid outcomes");  // Min 2 possible outcomes
        require(_liquidity >= tokenScale, "Invalid liquidity");  // Min 1 collateral unit (based on decimals)
        require(_overround >= 200, "Invalid overround");  // Min 2% overround (based on sensitivity)

        // Calculate min collateral needed based on liquidity and overround received (LS-LMSR max-loss formula)
        uint256 maxCollateralLoss = _liquidity.mul(_overround).div(10_000);
        require(_funding >= maxCollateralLoss, "Invalid funding");

        // Get initial funding tokens from sender (max theoretical loss + dust)
        IERC20(token).safeTransferFrom(msg.sender, address(this), _funding);

        // Call internal function to setup the market
        _setup(_id, _oracle, _outcomes, _liquidity, _overround);

        // Save initial collateral received by the market
        initialCollateral = _funding;
    }

    /**
     * @notice Internal function to setup the market with the received parameters
     */
    function _setup(uint256 _id, address _oracle, uint256 _outcomes, uint256 _liquidity, uint256 _overround) internal {
        // Save basic parameters
        id = uint32(_id);  // Should be less than the 4 billon limit
        oracle = _oracle;
        totalOutcomes = uint16(_outcomes);  // Should be less than 65 thousand limit
        initialShares = _fromTokenUnits(_liquidity);

        // Calculate initialization variables
        int128 n = ABDKMath.fromUInt(_outcomes);
        int128 overround = ABDKMath.divu(_overround, 10_000); // if the overround is too low the exp function overflows
        alpha = ABDKMath.div(overround, ABDKMath.mul(n, ABDKMath.ln(n)));
        shares = new int128[](_outcomes.add(1));
        for (uint256 outcome = 1; outcome <= _outcomes; outcome++) {
            shares[outcome] = initialShares;
            totalShares = ABDKMath.add(totalShares, initialShares);
        }

        // Initialize token leak mitigation of 0.001% (sellFee = 1/sellFeeFactor)
        // Note: Needed to avoid leaks due to rounding errors on math logarithmic and exponential approximations
        sellFeeFactor = ABDKMath.fromUInt(100_000);  // 100k as signed 64.64 bit fixed point

        // Calculate current cost on the market
        int128 beta = ABDKMath.mul(totalShares, alpha);
        currentCost = _cost(shares, beta);

        // Register successful setup and initialize reentrancy locks
        unlocked = 1;
    }

    /**
     * @notice Buys outcome shares for the specified outcome
     * @param _outcome The outcome of which shares are being bought (e.g.: 1 for YES, 2 for NO)
     * @param _amount The number of outcome shares to buy (as a signed 64.64-bit fixed point number)
     * @param _maxCost Max amount of collateral tokens to spend (0 = no limit, skip slippage check)
     * @return tokenCost The total token amount used for buying the specified amount of outcome shares
     */
    function buy(uint256 _outcome, int128 _amount, uint256 _maxCost) external lock
    returns (uint256 tokenCost) {
        // Send BUY call with msg sender as buyer and payer
        tokenCost = _buy(_outcome, _amount, msg.sender, msg.sender);
        if (_maxCost != 0) require(tokenCost <= _maxCost, "Buy cost too high");
    }

    /**
     * @notice Internal function to buy market shares for a specific buyer and payer
     * @param _outcome The outcome of which shares are being bought (e.g.: 1 for YES, 2 for NO)
     * @param _amount The number of outcome shares to buy (as a signed 64.64-bit fixed point number)
     * @param _buyer The address of the account that receives the outcome shares
     * @param _payer The address that pays the token cost of the trade (usually the buyer)
     * @return tokenCost The total token amount used for buying the specified amount of outcome shares
     */
    function _buy(uint256 _outcome, int128 _amount, address _buyer, address _payer) internal
    returns (uint256 tokenCost) {
        _checkOpenMarket();
        require(_outcome > 0 && _outcome <= totalOutcomes, "Invalid outcome");
        require(_amount > 0 && _amount % ONE_SHARE == 0, "Invalid amount");

        // Add amount of shares to be bought from specific outcome and calculate new total shares
        shares[_outcome] = ABDKMath.add(shares[_outcome], _amount);
        int128 newTotalShares = ABDKMath.add(totalShares, _amount);

        // Calculate new cost and tokens to receive (deltaCost)
        int128 newBeta = ABDKMath.mul(alpha, newTotalShares);
        int128 newCost = _cost(shares, newBeta);
        int128 deltaCost = ABDKMath.sub(newCost, currentCost);

        // Save new cost and new total shares of the market
        currentCost = newCost;
        totalShares = newTotalShares;

        // Get amount of tokens from sender (as current payment)
        tokenCost = _toTokenUnits(deltaCost);
        require(tokenCost > 0, "Invalid cost");
        IERC20(token).safeTransferFrom(_payer, address(this), tokenCost);
        uint256 outcomeShares = _toTokenUnits(_amount);

        // Register BUY in market total and Account details
        totalBuys += 1;  // SafeMath not needed here (max 2^64)
        AccountData storage account = accounts[_buyer];
        account.buys += 1;  // SafeMath not needed here (max 2^64)
        account.deposited = account.deposited.add(tokenCost);
        account.balances[_outcome] = account.balances[_outcome].add(outcomeShares);

        emit SharesBought(_buyer, _outcome, outcomeShares, tokenCost);
        return tokenCost;
    }

    /**
     * @notice Sells outcome shares for the specified outcome
     * @param _outcome The outcome of which shares are being sold (e.g.: 1 for YES, 2 for NO)
     * @param _amount The number of outcome shares to sell (as a signed 64.64-bit fixed point number)
     * @param _minReturn Min amount of collateral tokens to obtain (slippage protection)
     * @return tokenReturn The total amount of tokens received from selling the outcome shares
     */
    function sell(uint256 _outcome, int128 _amount, uint256 _minReturn) external lock
    returns (uint256 tokenReturn) {
        // Send SELL call to internal function with the msg sender as seller and receiver
        tokenReturn = _sell(_outcome, _amount, msg.sender, msg.sender);
        if (_minReturn != 0) require(tokenReturn >= _minReturn, "Sell return too low");
    }

    /**
     * @notice Internal function to sell market shares for a specific seller and receiver
     * @param _outcome The outcome for which shares are being sold (e.g.: 1 for YES, 2 for NO)
     * @param _amount The number of outcome shares to sell (as a signed 64.64-bit fixed point number)
     * @param _seller The address of the account that sells the shares balance
     * @param _receiver The address that receive the token return of the trade (usually the seller)
     * @return tokenReturn The total amount of tokens received from selling the outcome shares
     */
    function _sell(uint256 _outcome, int128 _amount, address _seller, address _receiver) internal
    returns (uint256 tokenReturn) {
        _checkOpenMarket();
        require(sellFeeFactor > 0, "Market sells disabled");
        require(_outcome > 0 && _outcome <= totalOutcomes, "Invalid outcome");
        require(_amount > 0 && _amount % ONE_SHARE == 0, "Invalid amount");

        // Get seller account from storage
        AccountData storage account = accounts[_seller];
        uint256 accountOutcomeBalance = account.balances[_outcome];

        // Check that the received account has the amount of shares to sell (account balance are in uint256)
        uint256 outcomeShares = _toTokenUnits(_amount);
        require(accountOutcomeBalance >= outcomeShares, "Insufficient shares");

        // Remove amount of shares to be sold from the specific outcome and calculate new total shares
        shares[_outcome] = ABDKMath.sub(shares[_outcome], _amount);
        int128 newTotalShares = ABDKMath.sub(totalShares, _amount);

        // Calculate new cost and tokens to return (deltaCost - sellFeeCost)
        int128 newBeta = ABDKMath.mul(alpha, newTotalShares);
        int128 newCost = _cost(shares, newBeta);
        int128 deltaCost = ABDKMath.sub(currentCost, newCost);
        require(deltaCost >= 0, "Invalid delta cost"); // Safety check
        int128 sellFeeCost = ABDKMath.div(deltaCost, sellFeeFactor);  // sellFee = 1/sellFeeFactor

        // Save new cost and new total shares of the market
        currentCost = newCost;
        totalShares = newTotalShares;

        // Calculate return amount of token to send (should be always positive or zero in extreme cases)
        tokenReturn = _toTokenUnits(ABDKMath.sub(deltaCost, sellFeeCost));

        // Register SELL in market total and Account details
        totalSells += 1;  // SafeMath not needed here (max 2^64)
        account.sells += 1;  // SafeMath not needed here (max 2^64)
        account.withdrawn = account.withdrawn.add(tokenReturn);
        account.balances[_outcome] = accountOutcomeBalance.sub(outcomeShares);

        // Transfer collateral tokens to the receiver account
        IERC20(token).safeTransfer(_receiver, tokenReturn);

        emit SharesSold(_seller, _outcome, outcomeShares, tokenReturn);
        return tokenReturn;
    }

    /**
     * @notice Internal function to open market state (used on `buy` and `sell`)
     */
    function _checkOpenMarket() internal view {
        uint64 start = startTimestamp;
        uint64 end = endTimestamp;
        uint64 close = closeTimestamp;

        require(block.timestamp >= start, "Market not started");
        require(end == 0 || block.timestamp <= end, "Market ended");
        require(close == 0, "Market already closed");
    }

    /**
     * @notice Redeems the current sender shares for the result of the market
     * @return redeemedShares The number of shares redeemed
     */
    function redeemShares() external lock returns (uint256 redeemedShares) {
        return _redeem(msg.sender);
    }

    /**
     * @notice Internal function to redeems winning shares for a specific account
     * @param _account The address of the account with winning shares of the market
     * @return redeemedShares The number of shares redeemed
     */
    function _redeem(address _account) internal returns (uint256 redeemedShares) {
        // Check current state of the market and received account
        require(closeTimestamp > 0, "Market not closed");
        require(accounts[_account].redeemed == 0, "Shares already redeemed");

        // Get amount of shares to be redeemed for received account
        redeemedShares = accounts[_account].balances[result];
        require(redeemedShares > 0, "Nothing to redeem");

        // Register amount of shares redeemed and send corresponding collateral tokens (ratio 1:1)
        totalRedeemedShares = ABDKMath.add(totalRedeemedShares, _fromTokenUnits(redeemedShares));
        accounts[_account].redeemed = redeemedShares;
        IERC20(token).safeTransfer(_account, redeemedShares);

        emit SharesRedeemed(_account, result, redeemedShares, redeemedShares);
        return redeemedShares;
    }

    /**
     * @notice Reports the result of the market (limited to only Oracle)
     * @param _id The unique identifier of the market
     * @param _outcome The outcome that is reported as the result of the market
     */
    function reportResult(uint256 _id, uint256 _outcome) external lock onlyOracle {
        require(_id == id, "Invalid market");
        require(_outcome > 0 && _outcome <= totalOutcomes, "Invalid outcome");

        // Check current state of the market
        require(block.timestamp > endTimestamp, "Market not ended");
        require(closeTimestamp == 0, "Market already closed");

        // Verify that the collateral on the market is higher than the redeemable collateral
        uint256 marketCollateral = IERC20(token).balanceOf(address(this));
        int128 winningShares = ABDKMath.sub(shares[_outcome], initialShares);
        uint256 redeemableCollateral = _toTokenUnits(winningShares);
        require(marketCollateral >= redeemableCollateral, "Market not closable");

        // Register reported result and current time
        result = uint16(_outcome);  // The index should be less than 65 thousand limit (same as total outcomes)
        closeTimestamp = uint64(block.timestamp);  // Should be less than 500 billon years

        emit ResultReported(msg.sender, result, closeTimestamp);
    }

    /**
     * @notice Redeems shares in batch for multiple accounts  (limited to only Oracle or Owner)
     * @param _accounts The list of accounts to redeem shares for (skips account if can not redeem)
     * @dev The list of accounts could be calculated using the "SharesBought" event
     * @return redeems The number of successful redeems
     */
    function redeemBatch(address[] memory _accounts) external lock onlyOracleOrOwner
    returns (uint256 redeems) {
        bool closed = closeTimestamp > 0;  // Cached variable
        require(closed, "Market not closed");
        require(_accounts.length <= 100, "Batch too large");

        uint16 winningOutcome = result;  // Cached variable
        for (uint256 i = 0; i < _accounts.length; i++) {
            AccountData storage account = accounts[_accounts[i]];
            if (closed && account.redeemed == 0 && account.balances[winningOutcome] > 0) {
                _redeem(_accounts[i]);
                redeems += 1;
            }
        }
        return redeems;
    }

    /**
     * @notice Authorize market owner to update start and end timestamps (limited to only Oracle)
     * @dev Used when the oracle authorize/request early market closure
     * @param _id The unique identifier of the market
     */
    function enableDatesUpdate(uint256 _id) external onlyOracle {
        require(_id == id, "Invalid market");
        require(!datesUpdateEnabled, "Date updates already enabled");

        // Enable market dates updates
        datesUpdateEnabled = true;
    }

    /**
     * @notice Execute internal buy for received buyer and payer (limited to only owner)
     * @dev No reentrancy guard - Owner (PrecogMaster) must use its own lock modifier (to avoid double-locking)
     * @param _buyer The address of the account that receives the outcome shares
     * @param _payer The address that pays the token cost of the trade (usually the buyer)
     * @param _outcome The outcome of which shares are being bought (e.g.: 1 for YES, 2 for NO)
     * @param _amount The number of outcome shares to buy (as a signed 64.64-bit fixed point number)
     * @return tokenCost The total token amount used for buying the specified amount of outcome shares
     */
    function buyFor(address _buyer, address _payer, uint256 _outcome, int128 _amount) external onlyOwner
    returns (uint256 tokenCost) {
        return _buy(_outcome, _amount, _buyer, _payer);
    }

    /**
     * @notice Execute internal sell for received seller and receiver (limited to only owner)
     * @dev No reentrancy guard - Owner (PrecogMaster) must use its own lock modifier (to avoid double-locking)
     * @param _seller The address of the account that sells the shares balance
     * @param _receiver The address that receive the token return of the trade (usually the seller)
     * @param _outcome The outcome for which shares are being sold (e.g.: 1 for YES, 2 for NO)
     * @param _amount The number of outcome shares to sell (as a signed 64.64-bit fixed point number)
     * @return tokenReturn The total amount of tokens received from selling the outcome shares
     */
    function sellFor(address _seller, address _receiver, uint256 _outcome, int128 _amount) external onlyOwner
    returns (uint256 tokenReturn) {
        return _sell(_outcome, _amount, _seller, _receiver);
    }

    /**
     * @notice Execute internal redeem for received account (limited to only owner)
     * @dev No reentrancy guard - Owner (PrecogMaster) must use its own lock modifier (to avoid double-locking)
     * @param _account The address of the account with winning shares of the market
     * @return redeemedShares The number of shares redeemed
     */
    function redeemFor(address _account) external onlyOwner returns (uint256 redeemedShares) {
        return _redeem(_account);
    }

    /**
     * @notice Updates the start and end timestamps for the market with oracle authorization (limited to only owner)
     * @param _newStartTimestamp The timestamp when the market starts allowing trading
     * @param _newEndTimestamp The timestamp when the market stops allowing trading
     */
    function updateDates(uint256 _newStartTimestamp, uint256 _newEndTimestamp) external onlyOwner {
        require(_newStartTimestamp <= _newEndTimestamp, "Invalid new dates");
        require(startTimestamp == 0 || datesUpdateEnabled, "Date updates disabled");

        startTimestamp = uint64(_newStartTimestamp);  // Should be less than 500 billon years
        endTimestamp = uint64(_newEndTimestamp);  // Should be less than 500 billon years

        // Revoke oracle authorization and emit event
        datesUpdateEnabled = false;
        emit DatesUpdated(msg.sender, startTimestamp, endTimestamp);
    }

    /**
     * @notice Update the oracle address of the market (limited to only owner)
     * @param _newOracle The address of the EOA or contract that can close the market
     */
    function updateOracle(address _newOracle) external onlyOwner {
        require(_newOracle != address(0), "Invalid new oracle");
        oracle = _newOracle;
    }

    /**
     * @notice Update the sell fee factor of the market (limited to only owner)
     * @param _newSellFeeFactor Used to calculate sell fees (1/sellFeeFactor) and mitigate leaks on math roundings
     */
    function updateSellFeeFactor(uint256 _newSellFeeFactor) external onlyOwner {
        // Note: Can't be lower than 0.001% to avoid token leaks due to rounding errors (sellFee = 1 / sellFeeFactor)
        require(_newSellFeeFactor <= 100_000, "Invalid new factor");
        sellFeeFactor = ABDKMath.fromUInt(_newSellFeeFactor);  // new value as signed 64.64 bit fixed point
    }

    /**
     * @notice Withdraws any remaining collateral from the market (limited to only owner)
     * @param _to The destination address of the ERC-20 collateral to withdraw
     */
    function withdrawAvailableCollateral(address _to) external lock onlyOwner returns (uint256 amount) {
        require(closeTimestamp > 0, "Market not closed");

        // Gets collateral amount available to be withdraw (taking into account past & future redeems)
        amount = getWithdrawableCollateral();

        // Transfer available tokens
        IERC20(token).safeTransfer(_to, amount);
        return amount;
    }

    /**
     * @notice Withdraws any non-collateral token or native balance received by the market (limited to only owner)
     * @dev Emergency function to rescue funds received by the market
     * @param _token The address of the ERC-20 token to withdraw
     */
    function withdraw(address _token) external lock onlyOwner returns (uint256 amount) {
        require(closeTimestamp > 0, "Market not closed");
        require(_token != token, "Invalid token");

        if (_token == address(0)) {
            amount = address(this).balance;
            (bool ok,) = msg.sender.call{value: amount}("");
            require(ok, "ETH withdraw failed");
        } else {
            amount = IERC20(_token).balanceOf(address(this));
            IERC20(_token).safeTransfer(msg.sender, amount);
        }
        return amount;
    }

    /**
     * @notice Transfers the ownership of the contract to a new owner (limited to only owner)
     * @param _newOwner The address of the new owner
     */
    function transferOwnership(address _newOwner) external virtual onlyOwner {
        require(_newOwner != address(0), "Invalid new owner");
        emit OwnershipTransferred(owner, _newOwner);
        owner = _newOwner;
    }

    /**
     * @notice Gets the cost of buying the specified amount of outcome shares
     * @param _outcome The outcome for which shares are being bought
     * @param _amount The number of outcome shares to buy (as signed 64.64-bit fixed point number)
     * @return tokenCost The token cost amount (as a signed 64.64-bit fixed point number)
     */
    function buyPrice(uint256 _outcome, int128 _amount) public view returns (int128 tokenCost) {
        require(_outcome > 0 && _outcome <= totalOutcomes, 'Invalid outcome');
        require(_amount > 0, 'Invalid amount');  // No integer-share validation to allow continuous price curves
        return ABDKMath.sub(_costAfterBuy(_outcome, _amount), currentCost);
    }

    /**
     * @notice Gets the return from selling the specified amount of outcome shares
     * @param _outcome The outcome for which shares are being sold
     * @param _amount The number of outcome shares to sell (as signed 64.64-bit fixed point number)
     * @return tokenReturn The token return amount (as a signed 64.64-bit fixed point number)
     */
    function sellPrice(uint256 _outcome, int128 _amount) public view returns (int128 tokenReturn) {
        require(_outcome > 0 && _outcome <= totalOutcomes, 'Invalid outcome');
        // Note: No integer-share validation to allow continuous price curves. Also validating against total minted
        require(_amount > 0 && _amount <= shares[_outcome], 'Invalid amount');
        int128 deltaCost = ABDKMath.sub(currentCost, _costAfterSell(_outcome, _amount));
        int128 sellFeeCost = ABDKMath.div(deltaCost, sellFeeFactor);
        return ABDKMath.sub(deltaCost, sellFeeCost);
    }

    /**
     * @notice Gets total collateral amount available to be withdraw after all winning shares redeems
     */
    function getWithdrawableCollateral() public view returns (uint256) {
        // No collateral is available to withdraw until a valid result is registered
        if (result == 0) {
            return 0;
        }

        // Get all collateral currently on the market
        uint256 marketCollateral = IERC20(token).balanceOf(address(this));

        // Calculate all collateral left to be redeemed by the winning shares (winning shares - already redeem)
        int128 winningShares = ABDKMath.sub(shares[result], initialShares);
        uint256 redeemableCollateral = _toTokenUnits(ABDKMath.sub(winningShares, totalRedeemedShares));

        return SafeMath.sub(marketCollateral, redeemableCollateral);
    }

    /**
     * @notice Gets the current market state information
     * @return totalShares The current total shares minted for all outcomes of the market
     * @return sharesBalances Balances of all outcomes (indexed by outcome)
     * @return totalRedeemedShares Total redeemed shares of the reported outcome
     * @return currentCost The current liquidity of the market
     * @return totalBuys Buys counter of the market
     * @return totalSells Sells counter of the market
     */
    function getMarketInfo() external view returns (int128, int128[] memory, int128, int128, uint256, uint256) {
        int128[] memory sharesBalances = new int128[](shares.length);

        // Verify if market setup was made
        if (unlocked == 0) {
            return (0, sharesBalances, 0, 0, 0, 0);
        }

        // Populate shares balances based on total outcomes configured for the market
        for (uint256 outcome = 1; outcome <= totalOutcomes; outcome++) {
            sharesBalances[outcome] = shares[outcome];
        }

        return (totalShares, sharesBalances, totalRedeemedShares, currentCost, totalBuys, totalSells);
    }

    /**
     * @notice Gets the market setup parameters
     * @return initialShares The total initial shares minted for each outcome [ qi ]
     * @return alpha The calculated alpha the market [ overround/(n.log(n)) ]
     * @return outcomes Total amount of possible outcomes of the market [ n ]
     * @return sellFeeFactor used to mitigate token leaks and calculate sell fees [ 1/sellFeeFactor ]
     * @return initialCollateral The total initial collateral received on market setup [ funding ]
     */
    function getMarketSetupInfo() external view returns (int128, int128, uint256, int128, uint256) {
        return (initialShares, alpha, totalOutcomes, sellFeeFactor, initialCollateral);
    }

    /**
     * @notice Gets current market buy and sell prices for all outcomes
     * @dev Helper function to fast calculate market prediction and spreads
     * @return buyPrices buy price of 1 share for all outcomes (indexed by outcome)
     * @return sellPrices sell price of 1 share for all outcomes (indexed by outcome)
     */
    function getPrices() external view returns (uint256[] memory buyPrices, uint256[] memory sellPrices) {
        buyPrices = new uint256[](shares.length);
        sellPrices = new uint256[](shares.length);
        for (uint256 outcome = 1; outcome <= totalOutcomes; outcome++) {
            buyPrices[outcome] = _toTokenUnits(buyPrice(outcome, ONE_SHARE));
            sellPrices[outcome] = _toTokenUnits(sellPrice(outcome, ONE_SHARE));
        }
        return (buyPrices, sellPrices);
    }

    /**
     * @notice Returns aggregated trading and settlement statistics for an account
     * @param _account Address of the account to query
     * @return buys Total number of buy operations executed by the account
     * @return sells Total number of sell operations executed by the account
     * @return deposited Total collateral deposited via buy operations
     * @return withdrawn Total collateral withdrawn via sell operations
     * @return redeemed Total collateral withdrawn via redeem operation (equal to total redeemed shares)
     */
    function getAccountStats(address _account) external view returns (
        uint256 buys, uint256 sells, uint256 deposited, uint256 withdrawn, uint256 redeemed
    ) {
        AccountData storage account = accounts[_account];
        return (account.buys, account.sells, account.deposited, account.withdrawn, account.redeemed);
    }

    /**
     * @notice Gets the amount of shares that an account owns for all outcomes
     * @param _account The address of the account to query
     * @return balances The balances of shares for all outcomes (indexed by outcome)
     */
    function getAccountOutcomeBalances(address _account) external view returns (uint256[] memory balances) {
        balances = new uint256[](shares.length);
        for (uint256 outcome = 1; outcome <= totalOutcomes; outcome++) {
            balances[outcome] = accounts[_account].balances[outcome];
        }
        return balances;
    }

    /**
     * @notice Get the total cost value in the market based on received parameters
     * @return totalCost The total cost in the form of a signed 64.64-bit fixed point number
     */
    function _cost(int128[] memory _shares, int128 _beta) internal pure returns (int128) {
        // Implementation based on LS-LMSR Formula: cost=b.ln(∑ e^(Qi/b))
        // Math fix: Avoid overflows using Log-Sum-Exp (LSE) function: ln(∑e^x) = c + ln(∑ e^(x-c)) with c=max(x)
        uint256 outcomes = _shares.length - 1;  // shares indexed start in 1

        // Find max exponent of the LS-LMSR formula: max(shares[outcome] / beta)
        int128 maxExponent = ABDKMath.div(_shares[1], _beta);
        for (uint256 i = 2; i <= outcomes; i++) {
            int128 x = ABDKMath.div(_shares[i], _beta);
            if (x > maxExponent) maxExponent = x;
        }

        // Calculate total sum of exp(x - maxExponent)
        int128 sum;
        for (uint256 i = 1; i <= outcomes; i++) {
            int128 x = ABDKMath.div(_shares[i], _beta);
            sum = ABDKMath.add(sum, ABDKMath.exp(ABDKMath.sub(x, maxExponent)));
        }

        // Return calculated cost = beta * (maxExponent + ln(sum))
        return ABDKMath.mul(_beta, ABDKMath.add(ABDKMath.ln(sum), maxExponent));
    }

    /**
     *  @notice Gets the total collateral value in the market after a received BUY trade (used in simulations)
     *  @dev Internal function used to calculate buy price
     */
    function _costAfterBuy(uint256 _outcome, int128 _amount) internal view returns (int128) {
        // Initialize and copy shares variable (on memory)
        int128[] memory newShares = new int128[](shares.length);
        for (uint256 outcome = 1; outcome <= totalOutcomes; outcome++) {
            newShares[outcome] = shares[outcome];
        }

        // Apply potential new trade to shares copy
        newShares[_outcome] = ABDKMath.add(newShares[_outcome], _amount);

        // Calculate potential new beta (based on new total shares and fixed alpha)
        int128 newBeta = ABDKMath.mul(alpha, ABDKMath.add(totalShares, _amount));

        // Return potential new cost after received trade
        return _cost(newShares, newBeta);
    }

    /**
     *  @notice Gets the total collateral value in the market after a received SELL trade (used in simulations)
     *  @dev Internal function used to calculate sell price
     */
    function _costAfterSell(uint256 _outcome, int128 _amount) internal view returns (int128) {
        // Initialize and copy shares variable (on memory)
        int128[] memory newShares = new int128[](shares.length);
        for (uint256 outcome = 1; outcome <= totalOutcomes; outcome++) {
            newShares[outcome] = shares[outcome];
        }

        // Apply potential new trade to shares copy
        newShares[_outcome] = ABDKMath.sub(newShares[_outcome], _amount);

        // Calculate potential new beta (based on new total shares and fixed alpha)
        int128 newBeta = ABDKMath.mul(alpha, ABDKMath.sub(totalShares, _amount));

        // Return potential new cost after received trade
        return _cost(newShares, newBeta);
    }

    /**
     * @notice Converts a signed 64.64 fixed-point amount (int128) into token units (uint256).
     * @dev Rounds to nearest instead of flooring when using `.mulu`.
     * @param _amount Amount in internal 64.64 fixed-point representation.
     * @return Token amount in smallest token units (e.g. wei).
     */
    function _toTokenUnits(int128 _amount) internal view returns (uint256) {
        // Increase result by half to avoid flooring error of `.mulu`
        int128 halfUnit = (int128(1) << 63) / int128(tokenScale);
        return ABDKMath.mulu(ABDKMath.add(_amount, halfUnit), tokenScale);
    }

    /**
     * @notice Converts a token amount (uint256) into signed 64.64 fixed-point format (int128).
     * @dev Used to normalize token amounts into the internal math representation.
     * @param _amount Token amount in smallest token units (e.g. wei).
     * @return Amount in internal 64.64 fixed-point representation.
     */
    function _fromTokenUnits(uint256 _amount) internal view returns (int128) {
        return ABDKMath.divu(_amount, tokenScale);
    }
}

contracts/PrecogMasterV7.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity 0.7.6;
pragma abicoder v2;

import "@openzeppelin/contracts/math/SafeMath.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import "@openzeppelin/contracts/proxy/Clones.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "./IPrecogToken.sol";
import "./IPrecogMarket.sol";

/**
 * @title PrecogMaster: Manager of prediction markets and Precog token claims
 * @author Marto (https://github.com/0xMarto)
 * @dev Feel free to make any adjustments to the code (DMs are open @0xMarto)
 */
contract PrecogMasterV7 is AccessControl {
    using SafeMath for uint256;
    using SafeERC20 for IERC20;
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant CALLER_ROLE = keccak256("CALLER_ROLE");
    bytes32 public constant MARKET_CREATOR_ROLE = keccak256("MARKET_CREATOR_ROLE");

    // State objects
    struct TokenClaim {
        address account;
        uint256 user;
        uint256 claimedAmount;
        uint256 claimedTimestamp;
    }

    struct MiningSeason {
        uint256 startTimestamp;
        uint256 endTimestamp;
        uint256 maxUserClaim;
        uint256 maxTotalClaim;
        uint256 maxTotalMint;
        uint256 claimedAmount;
        uint256 mintedAmount;
    }

    struct MarketInfo {
        string name;
        string description;
        string category;
        string outcomes;
        uint256 startTimestamp;
        uint256 endTimestamp;
        address creator;
        address market;
    }

    struct MarketConfig {
        uint256 totalOutcomes;
        uint256 funding;
        uint256 overround;
        address collateralToken;
        address collateralFunder;
        address marketOracle;
    }

    // Public variables
    address public token;  // Claim token and default collateral for non custom markets
    address private oracle; // default oracle for all non custom markets
    address private market; // base market recipe for all created markets
    uint256 public createdMarkets;  // Total markets created
    uint256 public currentSeason;  // Current claiming season number
    mapping(address => TokenClaim) public accountTokenClaims;
    mapping(uint256 => TokenClaim) public userTokenClaims;
    mapping(uint256 => MiningSeason) public miningSeasons;
    mapping(uint256 => MarketInfo) public markets;

    // Events emitted
    event TokensClaimed(address indexed account, uint256 indexed user, uint256 amount, uint256 timestamp);
    event TokensMinted(address indexed account, uint256 amount, uint256 timestamp);
    event MarketCreated(address indexed creator, uint256 id, address market);

    // Modifiers
    modifier onlyAdmin() {
        require(hasRole(ADMIN_ROLE, msg.sender), "Only Admin");
        _;
    }

    modifier onlyCaller() {
        require(hasRole(CALLER_ROLE, msg.sender), "Only Caller");
        _;
    }

    modifier onlyMarketCreator() {
        require(hasRole(MARKET_CREATOR_ROLE, msg.sender), "Only Market Creator");
        _;
    }

    // Functions
    constructor(address precogToken, address initialAdmin) {
        // Grant DEFAULT_ADMIN_ROLE to the initial admin (this is the admin to the ADMIN_ROLE list)
        _setupRole(DEFAULT_ADMIN_ROLE, initialAdmin);
        // Set ADMIN_ROLE as admin of CALLER_ROLE list
        _setRoleAdmin(CALLER_ROLE, ADMIN_ROLE);
        // Set already deployed precogToken as claimable token and collateral token for all Markets
        token = precogToken;
        // Grant ADMIN_ROLE to initial Admin (this enables to call "addAdmin" helper function)
        _setupRole(ADMIN_ROLE, initialAdmin);
    }

    /**
     * @notice Buys shares for the specified outcome in the desired market
     * @param marketId unique market identifier to trade
     * @param outcome The outcome of which shares are being bought (e.g.: 1 for YES, 2 for NO)
     * @param sharesAmount Number of outcome shares to buy (as a signed 64.64-bit fixed point number)
     * @param maxAmountIn Max amount of tokens able to spend in this trade (front-run mitigation)
     * @return amountIn Token amount used for buying the specified amount of shares
     */
    function marketBuy(
        uint256 marketId,
        uint256 outcome,
        int128 sharesAmount,
        uint256 maxAmountIn
    ) external returns (uint256 amountIn) {
        require(block.timestamp >= markets[marketId].startTimestamp, 'Market not started');
        require(block.timestamp <= markets[marketId].endTimestamp, 'Market already ended');

        // Get maxAmountIn of tokens from the buyer to Master (this reverts if there is no balance on buyer)
        address marketCollateral = IPrecogMarket(markets[marketId].market).token();
        if (marketCollateral == token) {
            // Case PrecogToken market: just move the max amount to this contract (no approve needed)
            IPrecogToken(token).move(msg.sender, address(this), maxAmountIn);
        } else {
            // Case custom token market: try to transfer from sender (this reverts is there is no allowance)
            IERC20(marketCollateral).safeTransferFrom(msg.sender, address(this), maxAmountIn);
        }

        // Send remote BUY to market contract (to be assigned to the sender)
        amountIn = IPrecogMarket(markets[marketId].market)._buy(outcome, sharesAmount, msg.sender);
        require(amountIn <= maxAmountIn, "Max amount reach!");  // Just in case there is some balance on this contract

        // If there is any leftover, return tokens to sender
        if (amountIn < maxAmountIn) {
            IERC20(marketCollateral).safeTransfer(msg.sender, maxAmountIn.sub(amountIn));
        }
        return amountIn;
    }

    /**
     * @notice Sells shares for the specified outcome in the desired market
     * @param marketId unique market identifier to trade
     * @param outcome The outcome of which shares are being sold (e.g.: 1 for YES, 2 for NO)
     * @param sharesAmount Number of outcome shares to sell (as a signed 64.64-bit fixed point number)
     * @param minAmountOut Min amount of tokens to obtain in this trade (front-run mitigation)
     * @return amountOut Token amount obtain from selling the specified amount of shares
     */
    function marketSell(
        uint256 marketId,
        uint256 outcome,
        int128 sharesAmount,
        uint256 minAmountOut
    ) external returns (uint256 amountOut) {
        require(block.timestamp >= markets[marketId].startTimestamp, "Market not started");
        require(block.timestamp <= markets[marketId].endTimestamp, "Market already ended");

        // Send remote SELL to market contract (to be assigned to the sender)
        amountOut = IPrecogMarket(markets[marketId].market)._sell(outcome, sharesAmount, msg.sender);

        // Check that the sell price was equal or higher seller expected
        require(amountOut >= minAmountOut, "Min amount reach!");

        return amountOut;
    }

    /**
     * @notice Redeems the total sender shares in the desired market
     * @param marketId unique market identifier to trade
     * @return shares Number of shares redeemed
     */
    function marketRedeemShares(uint256 marketId) external returns (uint256 shares) {
        return IPrecogMarket(markets[marketId].market)._redeem(msg.sender);
    }

    /**
     * @notice Gets the cost of buying the specified amount of outcome shares in the desired market
     * @param marketId unique market identifier to trade
     * @param outcome The outcome for which tokens are being bought
     * @param sharesAmount Number of outcome shares to buy (as signed 64.64-bit fixed point number)
     * @return tokenCost The token cost amount (as a signed 64.64-bit fixed point number)
     */
    function marketBuyPrice(uint256 marketId, uint256 outcome, int128 sharesAmount) external view
    returns (int128 tokenCost) {
        return IPrecogMarket(markets[marketId].market).buyPrice(outcome, sharesAmount);
    }

    /**
     * @notice Gets the return from selling the specified amount of outcome shares in the desired market
     * @param marketId unique market identifier to trade
     * @param outcome The outcome for which shares are being sold
     * @param sharesAmount The number of outcome shares to sell (as signed 64.64-bit fixed point number)
     * @return tokenReturn The token return amount (as a signed 64.64-bit fixed point number)
     */
    function marketSellPrice(uint256 marketId, uint256 outcome, int128 sharesAmount) external view
    returns (int128 tokenReturn) {
        return IPrecogMarket(markets[marketId].market).sellPrice(outcome, sharesAmount);
    }

    /**
     * @notice Gets market buy and sell prices for all outcomes of the desired market
     * @dev Helper function to fast calculate market prediction and spreads
     * @param marketId unique market identifier to trade
     * @return buyPrices buy price of 1 share for all outcomes (indexed by outcome)
     * @return sellPrices sell price of 1 share for all outcomes (indexed by outcome)
     */
    function marketPrices(uint256 marketId) external view
    returns (uint256[] memory buyPrices, uint256[] memory sellPrices) {
        return IPrecogMarket(markets[marketId].market).getPrices();
    }

    /**
     * @notice Gets market result summary of the desired market
     * @dev Helper function to show closed market info
     * @param marketId unique market identifier to trade
     * @return result Reported market result outcome
     * @return closed Timestamp when the market result was reported
     * @return reporter Address of the market result reporter (market oracle)
     */
    function marketResultInfo(uint256 marketId) external view
    returns (uint256 result, uint256 closed, address reporter) {
        IPrecogMarket createdMarket = IPrecogMarket(markets[marketId].market);

        // Get market result info
        result = createdMarket.result();
        closed = createdMarket.closeTimestamp();
        reporter = createdMarket.oracle();
        return (result, closed, reporter);
    }

    /**
     * @notice Gets market account shares summary of the desired market
     * @dev Helper function to show market info about an specific account
     * @param marketId unique market identifier to trade
     * @param account The address of the account with shares of the market
     * @return buys Total amount of Buys in the market
     * @return sells Total amount of Sells in the market
     * @return deposited Total amount of collateral deposited in the market
     * @return withdrew Total amount of collateral withdrew from the market
     * @return redeemed Total amount of collateral redeemed from the market
     * @return balances Account shares balances by outcome
     */
    function marketAccountShares(uint256 marketId, address account) external view
    returns (uint256 buys, uint256 sells, uint256 deposited, uint256 withdrew, uint256 redeemed,
        uint256[] memory balances) {
        IPrecogMarket createdMarket = IPrecogMarket(markets[marketId].market);
        // Get sharesInfo on received account for selected market
        (buys, sells, deposited, withdrew, redeemed) = createdMarket.accountShares(account);
        // Get outcome balances on received account for selected market
        balances = createdMarket.getAccountOutcomeBalances(account);
    }

    /**
     * @notice Gets the current market state info of the desired market
     * @dev Helper function to show general market shares info
     * @param marketId unique market identifier to trade
     * @return totalShares Current total shares minted for all outcomes of the market
     * @return sharesBalances All shares balances (indexed by outcome)
     * @return cost Current liquidity of the market
     * @return totalBuys Buys counter of the market
     * @return totalSells Sells counter of the market
     */
    function marketSharesInfo(uint256 marketId) external view
    returns (int128 totalShares, int128[] memory sharesBalances, int128 cost, uint256 totalBuys, uint256 totalSells) {
        IPrecogMarket createdMarket = IPrecogMarket(markets[marketId].market);
        (totalShares, sharesBalances, cost, totalBuys, totalSells) = createdMarket.getMarketInfo();
    }

    /**
     * @notice Gets the collateral info of the desired market
     * @dev Helper function to show data of a collateral of a market
     * @param marketId unique market identifier to trade
     * @return collateral Contract address of the market
     * @return name Token name of the market
     * @return symbol Token symbol of the market
     * @return decimals Token decimals of the market
     */
    function marketCollateralInfo(uint256 marketId) external view
    returns (address collateral, string memory name, string memory symbol, uint8 decimals) {
        IPrecogMarket createdMarket = IPrecogMarket(markets[marketId].market);
        IPrecogToken _collateral = IPrecogToken(createdMarket.token());
        return (address(_collateral), _collateral.name(), _collateral.symbol(), _collateral.decimals());
    }

    /**
     * @notice Helper function to check market close state
     */
    function isClosedMarket(uint256 marketId) external view returns (bool) {
        return IPrecogMarket(markets[marketId].market).closeTimestamp() > block.timestamp;
    }

    /**
     * @notice Helper function to check if some account has already redeemed market shares
     */
    function hasRedeemedShares(uint256 marketId, address account) external view returns (bool) {
        (,,,,uint256 redeemed) = IPrecogMarket(markets[marketId].market).accountShares(account);
        return redeemed > 0;
    }

    /**
     * @notice Helper function to check if some account has already claim current season tokens
     */
    function hasClaimed(address account, uint256 user) external view returns (bool) {
        return accountTokenClaims[account].claimedTimestamp != 0 || userTokenClaims[user].claimedTimestamp != 0;
    }

    // Whitelisted functions: Only caller & Only market creator
    function claimToken(address account, uint256 user, uint256 amount) external onlyCaller returns (bool) {
        // Validate token claim
        require(accountTokenClaims[account].claimedTimestamp == 0, "Account already claimed");
        require(userTokenClaims[user].claimedTimestamp == 0, "User already claimed");
        MiningSeason storage season = miningSeasons[currentSeason];
        if (season.startTimestamp > 0) {
            require(block.timestamp >= season.startTimestamp, "Season not started");
            require(block.timestamp < season.endTimestamp, "Season already ended");
            require(amount <= season.maxUserClaim, "Invalid user claim amount");
            require(amount.add(season.claimedAmount) <= season.maxTotalClaim, "Season max token claims");
            require(amount.add(season.mintedAmount) <= season.maxTotalMint, "Season max token mints");
        }

        // Register current token claim
        TokenClaim memory claim = TokenClaim({
            account: account,
            user: user,
            claimedAmount: amount,
            claimedTimestamp: block.timestamp
        });
        accountTokenClaims[account] = claim;
        userTokenClaims[user] = claim;
        season.claimedAmount = season.claimedAmount.add(amount);
        season.mintedAmount = season.mintedAmount.add(amount);

        // Mint tokens to received account
        IPrecogToken(token).mint(account, amount);

        emit TokensClaimed(account, user, amount, block.timestamp);
        return true;
    }

    function createMarket(
        string memory name,
        string memory description,
        string memory category,
        string[] memory outcomes,
        uint256 startTimestamp,
        uint256 endTimestamp,
        address creator,
        uint256 funding,
        uint256 overround
    ) external onlyCaller returns (uint256 newMarketId) {
        // Mint tokens to seed the new market
        IPrecogToken(token).mint(address(this), funding);

        // Pack all received information (with defaults), create new market and return new market id
        MarketInfo memory marketInfo = MarketInfo(
            name, description, category, arrayToCSV(outcomes), startTimestamp, endTimestamp, creator, address(0)
        );
        MarketConfig memory marketConfig = MarketConfig(
            outcomes.length, // Total number of outcomes
            funding,         // Initial supply of the market
            overround,       // AMM profit margin
            token,           // collateralToken: Precog Token
            address(this),   // collateralFunder: This contract
            oracle           // marketOracle: Preset oracle
        );
        return _createMarket(marketInfo, marketConfig);
    }

    function createCustomMarket(
        string memory name,
        string memory description,
        string memory category,
        string[] memory outcomes,
        uint256 startTimestamp,
        uint256 endTimestamp,
        address creator,
        uint256 funding,
        uint256 overround,
        address collateralToken,
        address collateralFunder,
        address marketOracle
    ) public onlyMarketCreator returns (uint256 newMarketId) {
        // Pack all received information, create new market and return new market id
        MarketInfo memory marketInfo = MarketInfo(
            name, description, category, arrayToCSV(outcomes), startTimestamp, endTimestamp, creator, address(0)
        );
        MarketConfig memory marketConfig = MarketConfig(
            outcomes.length, funding, overround, collateralToken, collateralFunder, marketOracle
        );
        return _createMarket(marketInfo, marketConfig);
    }

    function _createMarket(MarketInfo memory info, MarketConfig memory config) internal returns (uint256 newMarketId) {
        // Deploy a new market contract and initialize it with the collateral token
        address newMarketAddress = Clones.clone(market);
        IPrecogMarket newMarket = IPrecogMarket(newMarketAddress);
        newMarket.initialize(config.collateralToken);

        // Get funding amount to seed the new market (optimization: except in a self-funder usecase)
        if (config.collateralFunder != address(this)) {
            IERC20(config.collateralToken).safeTransferFrom(config.collateralFunder, address(this), config.funding);
        }
        // Pre approve all trades with
        IERC20(config.collateralToken).approve(newMarketAddress, type(uint256).max);

        // Get new Id and Setup deployed new market
        newMarketId = createdMarkets;
        newMarket.setup(newMarketId, config.marketOracle, config.totalOutcomes, config.funding, config.overround);
        newMarket.updateDates(info.startTimestamp, info.endTimestamp);

        // Save created market address in received info and save it in local storage (indexed by id)
        info.market = newMarketAddress;
        markets[newMarketId] = info;

        // Increase created markets counter and return new market id
        createdMarkets = createdMarkets.add(1);

        emit MarketCreated(info.creator, newMarketId, newMarketAddress);
        return newMarketId;
    }

    function arrayToCSV(string[] memory array) internal pure returns (string memory) {
        bytes memory csvBytes;
        for (uint i = 0; i < array.length; i++) {
            csvBytes = abi.encodePacked(csvBytes, array[i]);
            if (i < array.length - 1) {
                csvBytes = abi.encodePacked(csvBytes, ",");
            }
        }
        return string(csvBytes);
    }

    // Whitelisted functions: Only admin
    function addMarketCreator(address account) external onlyAdmin {
        grantRole(MARKET_CREATOR_ROLE, account);
    }

    function removeMarketCreator(address account) external onlyAdmin {
        revokeRole(MARKET_CREATOR_ROLE, account);
    }

    function addCaller(address account) external onlyAdmin {
        grantRole(CALLER_ROLE, account);
    }

    function removeCaller(address account) external onlyAdmin {
        revokeRole(CALLER_ROLE, account);
    }

    function addAdmin(address account) external onlyAdmin {
        grantRole(ADMIN_ROLE, account);
    }

    function removeAdmin(address account) external onlyAdmin {
        revokeRole(ADMIN_ROLE, account);
    }

    function updateCurrentSeason(uint256 seasonIndex) external onlyAdmin {
        currentSeason = seasonIndex;
    }

    function setMiningSeason(
        uint256 seasonIndex,
        uint256 startTimestamp,
        uint256 endTimestamp,
        uint256 maxUserClaim,
        uint256 maxTotalClaim,
        uint256 maxTotalMint,
        uint256 claimedAmount,
        uint256 mintedAmount
    ) external onlyAdmin {
        miningSeasons[seasonIndex] = MiningSeason({
            startTimestamp: startTimestamp,
            endTimestamp: endTimestamp,
            maxUserClaim: maxUserClaim,
            maxTotalClaim: maxTotalClaim,
            maxTotalMint: maxTotalMint,
            claimedAmount: claimedAmount,
            mintedAmount: mintedAmount
        });
    }

    function setBaseOracle(address _oracle) external onlyAdmin {
        oracle = _oracle;
    }

    function setBaseMarket(address _market) external onlyAdmin {
        market = _market;
    }

    function updateMarket(
        uint256 id,
        string memory name,
        string memory description,
        string memory category,
        string[] memory outcomes,
        uint256 startTimestamp,
        uint256 endTimestamp,
        address marketCreator,
        address marketOracle
    ) external onlyAdmin {
        if (bytes(name).length > 0) {
            markets[id].name = name;
        }
        if (bytes(description).length > 0) {
            markets[id].description = description;
        }
        if (bytes(category).length > 0) {
            markets[id].category = category;
        }
        if (outcomes.length > 0) {
            // Only updates outcome labels (not total possible outcomes)
            markets[id].outcomes = arrayToCSV(outcomes);
        }
        if (marketCreator != address(0)) {
            markets[id].creator = marketCreator;
        }
        if (marketOracle != address(0)) {
            IPrecogMarket(markets[id].market).updateOracle(marketOracle);
        }
        bool updateDates = false;
        if (startTimestamp > 0) {
            markets[id].startTimestamp = startTimestamp;
            updateDates = true;
        }
        if (endTimestamp > 0) {
            markets[id].endTimestamp = endTimestamp;
            updateDates = true;
        }
        if (updateDates) {
            IPrecogMarket(markets[id].market).updateDates(markets[id].startTimestamp, markets[id].endTimestamp);
        }
    }

    function marketWithdraw(uint256 marketId, address marketToken) external onlyAdmin {
        IPrecogMarket(markets[marketId].market).withdraw(marketToken);
    }

    function marketTransferOwnership(uint256 marketId, address newOwner) external onlyAdmin {
        IPrecogMarket(markets[marketId].market).transferOwnership(newOwner);
    }

    function updateTokenClaim(address account, uint256 amount, uint256 timestamp) external onlyAdmin {
        // Used to reset token claims
        accountTokenClaims[account].claimedAmount = amount;
        accountTokenClaims[account].claimedTimestamp = timestamp;
        uint256 user = accountTokenClaims[account].user;
        userTokenClaims[user].claimedAmount = amount;
        userTokenClaims[user].claimedTimestamp = timestamp;
    }

    function precogMint(address to, uint256 amount) external onlyAdmin {
        // Validate token mint
        MiningSeason storage season = miningSeasons[currentSeason];
        if (season.startTimestamp > 0) {
            require(amount.add(season.mintedAmount) <= season.maxTotalMint, "Season max token mints");
        }

        // Register token mint
        season.mintedAmount = season.mintedAmount.add(amount);

        // Mint tokens to received account
        IPrecogToken(token).mint(to, amount);

        emit TokensMinted(to, amount, block.timestamp);
    }

    function precogBurn(address from, uint256 amount) external onlyAdmin {
        IPrecogToken(token).burn(from, amount);
    }

    function precogTransferOwnership(address newPrecogMaster) external onlyAdmin {
        IPrecogToken(token).transferOwnership(newPrecogMaster);
    }

    function withdraw(address _token) public onlyAdmin {
        if (_token == address(0)) {
            payable(msg.sender).transfer(address(this).balance);
        } else {
            IERC20(_token).safeTransfer(msg.sender, IERC20(_token).balanceOf(address(this)));
        }
    }
}

contracts/PrecogMasterV8.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity 0.7.6;
pragma abicoder v2;

import "@openzeppelin/contracts/math/SafeMath.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import "@openzeppelin/contracts/proxy/Clones.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "./IPermitsMin.sol";
import "./IPrecogMarketV8.sol";
import "./IPrecogToken.sol";

/**
 * @title PrecogMaster: Manager and factory of Precog markets
 * @author Marto (https://github.com/0xMarto)
 * @dev Feel free to leave any code improvements (DMs are open @0xMarto)
 */
contract PrecogMasterV8 is AccessControl {
    using SafeMath for uint256;
    using SafeERC20 for IERC20;
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant CALLER_ROLE = keccak256("CALLER_ROLE");
    bytes32 public constant MARKET_OPERATOR_ROLE = keccak256("MARKET_OPERATOR_ROLE");
    address public constant PERMIT2 = 0x000000000022D473030F116dDEE9F6B43aC78BA3;

    // State objects
    struct MarketData {
        string question;
        string resolutionCriteria;
        string imageURL;
        string category;
        string outcomes;
        address creator;
        address operator;
        address market;
        uint256 startTimestamp;  // Market reference variable (cached for gas optimization)
        uint256 endTimestamp;  // Market reference variable (cached for gas optimization)
        address collateral;  // Market reference variable (cached for gas optimization)
    }

    struct MarketConfig {
        address oracle;
        uint256 totalOutcomes;
        uint256 liquidity;
        uint256 overround;
        int256 sellFeeFactor;
        uint256 collateralFunding;
        address collateralFunder;
    }

    // Public variables
    uint256 public createdMarkets;  // Total markets created
    mapping(uint256 => MarketData) public markets;  // Market data of created markets
    mapping(address => bool) public allowedOracles;  // Whitelisted market oracles for market operators
    mapping(address => bool) public allowedCollaterals;  // Whitelisted market collaterals for market operators
    mapping(address => bool) public allowedReceivers;  // Allowed receivers of market funding withdrawals
    mapping(address => bool) public ownedCollaterals;  // Special collaterals owned by this contract

    // Private variables
    address private baseMarket; // Market recipe for all created markets by this contract
    uint256 private marketMinOverround;  // Min overround for market operators
    int256 private marketMinSellFeeFactor;  // Max sell fee overround for market operators (negative means disabled)
    uint256 private protocolFeeFactor;  // Used to calculate protocol fee for market operators
    uint8 private unlocked;  // No reentrancy flag

    // Events emitted
    event MarketCreated(address indexed creator, address indexed operator, uint256 id, address market);

    // Modifiers
    modifier onlyAdmin() {
        require(hasRole(ADMIN_ROLE, msg.sender), "Only Admin");
        _;
    }

    modifier onlyCaller() {
        require(hasRole(CALLER_ROLE, msg.sender), "Only Caller");
        _;
    }

    modifier onlyMarketOperator() {
        require(hasRole(MARKET_OPERATOR_ROLE, msg.sender), "Only Market Operator");
        _;
    }

    modifier lock() {
        require(unlocked == 1, "Locked");
        unlocked = 2;   // Activate lock! (enter critical section)
        _;
        unlocked = 1;   // Deactivate lock! (exit critical section)
    }

    // Functions
    constructor(address initialAdmin) {
        // Grant DEFAULT_ADMIN_ROLE to the initial admin (this is the admin to the ADMIN_ROLE list)
        _setupRole(DEFAULT_ADMIN_ROLE, initialAdmin);
        // Set ADMIN_ROLE as admin of CALLER_ROLE list
        _setRoleAdmin(CALLER_ROLE, ADMIN_ROLE);
        // Grant ADMIN_ROLE to initial Admin (this enables to call "addAdmin" helper function)
        _setupRole(ADMIN_ROLE, initialAdmin);
    }

    /**
     * @notice Buys shares for the specified outcome in the desired market
     * @param marketId Unique market identifier to trade
     * @param outcome The outcome index of which shares are being bought (e.g.: 1 for YES, 2 for NO)
     * @param sharesAmount Number of outcome shares to buy (as a signed 64.64-bit fixed point number)
     * @param maxAmountIn Max amount of collateral tokens willing to spend (slippage protection)
     * @return amountIn Actual amount of collateral tokens spent on the trade
     */
    function marketBuy(uint256 marketId, uint256 outcome, int128 sharesAmount, uint256 maxAmountIn) external lock
    returns (uint256 amountIn) {
        // Get market and collateral from received market id
        MarketData storage marketData = markets[marketId];
        IERC20 marketCollateral = IERC20(marketData.collateral);

        // Get maxAmountIn of tokens from the buyer to this contract (this reverts if there is no balance or allowance)
        marketCollateral.safeTransferFrom(msg.sender, address(this), maxAmountIn);

        // Send special BUY to market contract (with the sender as `buyer` and this contract as `payer`)
        amountIn = IPrecogMarketV8(marketData.market).buyFor(msg.sender, address(this), outcome, sharesAmount);
        require(amountIn <= maxAmountIn, "Buy cost too high");

        // If there is any leftover, return tokens to sender
        if (amountIn < maxAmountIn) {
            marketCollateral.safeTransfer(msg.sender, maxAmountIn - amountIn);  // SafeMath not needed (validated)
        }
        return amountIn;
    }

    /**
     * @notice Buys shares using EIP-2612 permit signature for gasless approval (advanced, gas-optimized path)
     * @dev The permit signature must approve the Market contract directly (not Master) as the spender.
     * @param marketId Unique market identifier to trade
     * @param outcome The outcome index of which shares are being bought (e.g.: 1 for YES, 2 for NO)
     * @param sharesAmount Number of outcome shares to buy (as a signed 64.64-bit fixed point number)
     * @param maxAmountIn Max amount of collateral tokens willing to spend (slippage protection)
     * @param deadline Unix timestamp after which the permit signature expires
     * @param v Recovery byte of the ECDSA signature
     * @param r First 32 bytes of the ECDSA signature
     * @param s Second 32 bytes of the ECDSA signature
     * @return amountIn Actual amount of collateral tokens spent on the trade
     */
    function marketBuyWithPermit(
        uint256 marketId, uint256 outcome, int128 sharesAmount, uint256 maxAmountIn,
        uint256 deadline, uint8 v, bytes32 r, bytes32 s
    ) external lock returns (uint256 amountIn) {
        // Get market and token addresses from received market id
        address market = markets[marketId].market;
        address token = markets[marketId].collateral;

        // Give allowance from the sender to received market contract with permit (eip-2612) signature
        // Dev Note: The signature should be sign with the Market instance as spender (to avoid extra gas costs)
        IERC20Permit(token).permit(msg.sender, market, maxAmountIn, deadline, v, r, s);

        // Send special BUY to market contract (with the sender as `buyer` and `payer`)
        amountIn = IPrecogMarketV8(market).buyFor(msg.sender, msg.sender, outcome, sharesAmount);
        require(amountIn <= maxAmountIn, "Buy cost too high");

        // Return actual token cost
        return amountIn;
    }

    /**
     * @notice Buys shares using Permit2 signature for gasless approval (single transaction, any token)
     * @dev This function uses Uniswap's Permit2 contract for signature-based token transfers.
     * @param marketId Unique market identifier to trade
     * @param outcome The outcome index of which shares are being bought (e.g.: 1 for YES, 2 for NO)
     * @param sharesAmount Number of outcome shares to buy (as a signed 64.64-bit fixed point number)
     * @param maxAmountIn Max amount of collateral tokens willing to spend (slippage protection)
     * @param nonce Unique value to prevent signature replay (from Permit2 contract)
     * @param deadline Unix timestamp after which the permit signature expires
     * @param sig Permit2 signature authorizing the transfer
     * @return amountIn Actual amount of collateral tokens spent on the trade
     */
    function marketBuyWithPermit2(
        uint256 marketId, uint256 outcome, int128 sharesAmount, uint256 maxAmountIn,
        uint256 nonce, uint256 deadline, bytes calldata sig
    ) external lock returns (uint256 amountIn) {
        // Get market and collateral from received market id
        MarketData storage marketData = markets[marketId];
        address marketCollateral = marketData.collateral;

        // Get maxAmountIn of tokens from the buyer to this contract with Permit2 signature
        _permit2TransferFrom(marketCollateral, msg.sender, address(this), maxAmountIn, nonce, deadline, sig);

        // Send special BUY to market contract (with the sender as `buyer` and this contract as `payer`)
        amountIn = IPrecogMarketV8(marketData.market).buyFor(msg.sender, address(this), outcome, sharesAmount);
        require(amountIn <= maxAmountIn, "Buy cost too high");

        // If there is any leftover, return tokens to sender
        if (amountIn < maxAmountIn) {
            IERC20(marketCollateral).safeTransfer(msg.sender, maxAmountIn - amountIn);  // SafeMath not needed (validated)
        }
        return amountIn;
    }

    function _permit2TransferFrom(
        address token, address owner, address to, uint256 amount, uint256 nonce, uint256 deadline, bytes calldata sig
    ) internal {
        IPermit2(PERMIT2).permitTransferFrom(
            IPermit2.PermitTransferFrom(
                IPermit2.TokenPermissions(token, amount),
                nonce,
                deadline
            ),
            IPermit2.SignatureTransferDetails(to, amount),
            owner,
            sig
        );
    }

    /**
     * @notice Buys shares for the specified outcome in a owned collateralized market (advanced, non-approve path)
     * @param marketId Unique market identifier to trade
     * @param outcome The outcome index of which shares are being bought (e.g.: 1 for YES, 2 for NO)
     * @param sharesAmount Number of outcome shares to buy (as a signed 64.64-bit fixed point number)
     * @param maxAmountIn Max amount of collateral tokens willing to spend (slippage protection)
     * @return amountIn Actual amount of collateral tokens spent on the trade
     */
    function ownedMarketBuy(uint256 marketId, uint256 outcome, int128 sharesAmount, uint256 maxAmountIn) external lock
    returns (uint256 amountIn) {
        // Validate collateral based on received market id
        address marketCollateral = markets[marketId].collateral;
        require(ownedCollaterals[marketCollateral], "Not owned collateral");

        // Move the max amount to this contract (no approve needed)
        IPrecogToken(marketCollateral).move(msg.sender, address(this), maxAmountIn);

        // Send special BUY to market contract (with the sender as `buyer` and this contract as `payer`)
        amountIn = IPrecogMarketV8(markets[marketId].market).buyFor(msg.sender, address(this), outcome, sharesAmount);
        require(amountIn <= maxAmountIn, "Buy cost too high");

        // If there is any leftover, return tokens to sender
        if (amountIn < maxAmountIn) {
            IERC20(marketCollateral).safeTransfer(msg.sender, maxAmountIn.sub(amountIn));
        }
        return amountIn;
    }

    /**
     * @notice Sells shares for the specified outcome in the desired market
     * @param marketId Unique market identifier to trade
     * @param outcome The outcome of which shares are being sold (e.g.: 1 for YES, 2 for NO)
     * @param sharesAmount Number of outcome shares to sell (as a signed 64.64-bit fixed point number)
     * @param minAmountOut Min amount of collateral tokens to obtain (slippage protection)
     * @return amountOut Token amount obtain from selling the specified amount of shares
     */
    function marketSell(uint256 marketId, uint256 outcome, int128 sharesAmount, uint256 minAmountOut) external lock
    returns (uint256 amountOut) {
        // Note: All input validations are enforced at the Market layer

        // Send special SELL to market contract (with the sender as `seller` and `receiver`)
        amountOut = IPrecogMarketV8(markets[marketId].market).sellFor(msg.sender, msg.sender, outcome, sharesAmount);

        // Check that the sell price was equal or higher seller expected
        require(amountOut >= minAmountOut, "Sell return too low");

        return amountOut;
    }

    /**
     * @notice Redeems the total sender shares in the desired market
     * @param marketId Unique market identifier
     * @return shares Number of shares redeemed
     */
    function marketRedeemShares(uint256 marketId) external returns (uint256 shares) {
        return IPrecogMarketV8(markets[marketId].market).redeemFor(msg.sender);
    }

    /**
     * @notice Gets the cost of buying the specified amount of outcome shares in the desired market
     * @param marketId Unique market identifier to trade
     * @param outcome The outcome for which tokens are being bought
     * @param sharesAmount Number of outcome shares to buy (as signed 64.64-bit fixed point number)
     * @return tokenCost The token cost amount (as a signed 64.64-bit fixed point number)
     */
    function marketBuyPrice(uint256 marketId, uint256 outcome, int128 sharesAmount) external view
    returns (int128 tokenCost) {
        return IPrecogMarketV8(markets[marketId].market).buyPrice(outcome, sharesAmount);
    }

    /**
     * @notice Gets the return from selling the specified amount of outcome shares in the desired market
     * @param marketId Unique market identifier to trade
     * @param outcome The outcome for which shares are being sold
     * @param sharesAmount The number of outcome shares to sell (as signed 64.64-bit fixed point number)
     * @return tokenReturn The token return amount (as a signed 64.64-bit fixed point number)
     */
    function marketSellPrice(uint256 marketId, uint256 outcome, int128 sharesAmount) external view
    returns (int128 tokenReturn) {
        return IPrecogMarketV8(markets[marketId].market).sellPrice(outcome, sharesAmount);
    }

    /**
     * @notice Gets market buy and sell prices for all outcomes of the desired market
     * @dev Helper function to fast calculate market prediction and spreads
     * @param marketId unique market identifier to trade
     * @return buyPrices buy price of 1 share for all outcomes (indexed by outcome)
     * @return sellPrices sell price of 1 share for all outcomes (indexed by outcome)
     */
    function marketPrices(uint256 marketId) external view
    returns (uint256[] memory buyPrices, uint256[] memory sellPrices) {
        return IPrecogMarketV8(markets[marketId].market).getPrices();
    }

    /**
     * @notice Gets market result summary of the desired market
     * @dev Helper function to show closed market info
     * @param marketId unique market identifier to trade
     * @return result Reported market result outcome
     * @return closed Timestamp when the market result was reported
     * @return reporter Address of the market result reporter (market oracle)
     */
    function marketResultInfo(uint256 marketId) external view
    returns (uint256 result, uint256 closed, address reporter) {
        IPrecogMarketV8 createdMarket = IPrecogMarketV8(markets[marketId].market);

        // Get market result info
        result = createdMarket.result();
        closed = createdMarket.closeTimestamp();
        reporter = createdMarket.oracle();
        return (result, closed, reporter);
    }

    /**
     * @notice Gets the market setup parameters
     * @dev Helper function to show market setup info
     * @return initialShares The total initial shares minted for each outcome [ qi ]
     * @return alpha The calculated alpha the market [ overround/(n.log(n)) ]
     * @return outcomes Total amount of possible outcomes of the market [ n ]
     * @return sellFeeFactor used to mitigate token leaks and calculate sell fees [ 1/sellFeeFactor ]
     * @return initialCollateral The total initial collateral received on market setup [ funding ]
     */
    function marketSetupInfo(uint256 marketId) external view
    returns (int128 initialShares, int128 alpha, uint256 outcomes, int128 sellFeeFactor, uint256 initialCollateral) {
        IPrecogMarketV8 createdMarket = IPrecogMarketV8(markets[marketId].market);
        (initialShares, alpha, outcomes, sellFeeFactor, initialCollateral) = createdMarket.getMarketSetupInfo();
    }

    /**
     * @notice Gets the current market state info of the desired market
     * @dev Helper function to show general market shares info
     * @param marketId unique market identifier
     * @return totalShares Current total shares minted for all outcomes of the market
     * @return sharesBalances All shares balances (indexed by outcome)
     * @return redeemed Total redeemed shares of the reported outcome
     * @return cost Total redeemed shares of the reported outcome
     * @return buys Buys counter of the market
     * @return sells Sells counter of the market
     */
    function marketSharesInfo(uint256 marketId) external view returns (
        int128 totalShares, int128[] memory sharesBalances, int128 redeemed, int128 cost, uint256 buys, uint256 sells
    ) {
        IPrecogMarketV8 createdMarket = IPrecogMarketV8(markets[marketId].market);
        (totalShares, sharesBalances, redeemed, cost, buys, sells) = createdMarket.getMarketInfo();
    }

    /**
     * @notice Gets market account information for a specific market
     * @dev Returns trading statistics and outcome share balances for an account in the specified market.
     * @param marketId Unique market identifier
     * @param account Address of the account to query
     * @return buys Total number of buy transactions executed by this account
     * @return sells Total number of sell transactions executed by this account
     * @return deposited Total collateral deposited through buy transactions (cumulative)
     * @return withdrawn Total collateral withdrawn through sell transactions (cumulative)
     * @return redeemed Total collateral redeemed after market closure (0 if not redeemed yet)
     * @return balances Share balances for each outcome, indexed by outcome (balances[0] always unused)
     */
    function marketAccountInfo(uint256 marketId, address account) external view returns (
        uint256 buys, uint256 sells, uint256 deposited, uint256 withdrawn, uint256 redeemed, uint256[] memory balances
    ) {
        IPrecogMarketV8 market = IPrecogMarketV8(markets[marketId].market);
        // Get trading stats on received account for selected market
        (buys, sells, deposited, withdrawn, redeemed) = market.getAccountStats(account);
        // Get outcome balances on received account for selected market
        balances = market.getAccountOutcomeBalances(account);
    }

    /**
     * @notice Gets collateral token information for a specific market
     * @dev Returns ERC20 token details (address, name, symbol, decimals) used on the market
     * @param marketId Unique market identifier
     * @return token Collateral token contract address
     * @return name Token name (e.g., "USD Coin")
     * @return symbol Token symbol (e.g., "USDC")
     * @return decimals Token decimals (e.g., 6 for USDC, 18 for DAI)
     */
    function marketCollateralInfo(uint256 marketId) external view
    returns (address token, string memory name, string memory symbol, uint8 decimals) {
        IPrecogToken collateral = IPrecogToken(markets[marketId].collateral);
        return (address(collateral), collateral.name(), collateral.symbol(), collateral.decimals());
    }

    /**
     * @notice Gets the global market creation configuration and protocol parameters
     * @dev Returns parameters used to validate and configure new markets created by operators.
     * @return implementation Address of the base market implementation contract used for cloning
     * @return minOverround Minimum overround (in basis points) required for market creation
     * @return minSellFeeFactor Minimum sell fee factor allowed (negative value disables validation)
     * @return feeFactor Protocol fee factor used to calculate fees on market profits (fee = 1 / feeFactor)
     */
    function getMarketsConfigs() external view
    returns (address implementation, uint256 minOverround, int256 minSellFeeFactor, uint256 feeFactor) {
        return (baseMarket, marketMinOverround, marketMinSellFeeFactor, protocolFeeFactor);
    }

    /*//////////////////////////////////////////////////////////////
                        MARKET OPERATOR FUNCTIONS
    //////////////////////////////////////////////////////////////*/

    /**
     * @notice Creates a new prediction market with the specified configuration
     * @dev Deploys a minimal proxy clone of the base market implementation. Only callable by market operators.
     * @param data Market metadata including question, resolution criteria, outcomes, dates, and collateral
     * @param config Market parameters including oracle, liquidity, overround, and fee settings
     * @return newMarketId Unique identifier for the newly created market
     */
    function createMarket(MarketData memory data, MarketConfig memory config) external onlyMarketOperator
    returns (uint256 newMarketId) {
        // Validate market data variables
        require(bytes(data.question).length > 0, "Invalid question");
        require(bytes(data.resolutionCriteria).length > 0, "Invalid resolution criteria");
        require(bytes(data.outcomes).length > 0, "Invalid outcomes");
        require(allowedCollaterals[data.collateral], 'Collateral not allowed');
        require(data.startTimestamp <= data.endTimestamp, "Invalid dates");

        // Validate market config variables
        require(allowedOracles[config.oracle], 'Oracle not allowed');
        require(config.liquidity >= config.collateralFunding, 'Invalid liquidity');
        require(config.overround >= marketMinOverround, 'Invalid overround');
        require(config.sellFeeFactor >= marketMinSellFeeFactor, 'Invalid sell fee factor');
        require(config.collateralFunder == msg.sender, 'Invalid funder');

        // Populate fields controlled by this contract
        data.operator = msg.sender;
        data.market = address(0);

        newMarketId = _createMarket(data, config);
        return newMarketId;
    }

    /**
     * @notice Internal function to deploy and configure a new market contract
     * @dev Clones the base market implementation, transfers collateral and initializes market parameters.
     *      Market Data and Config parameter validation are made on `createMarket` external function
     * @param md Market metadata (question, dates, collateral, etc.)
     * @param mc Market configuration (oracle, liquidity, fees, etc.)
     * @return newMarketId The ID assigned to the newly created market
     *
     * Market Types:
     * - Full Liquidity: liquidity == collateralFunding (all liquidity backed by real collateral)
     * - Virtual Liquidity: liquidity > collateralFunding (liquidity backed by max collateral loss calculation)
     */
    function _createMarket(MarketData memory md, MarketConfig memory mc) internal returns (uint256) {
        // Deploy a new market contract and initialize it with the collateral token
        address newMarketAddress = Clones.clone(baseMarket);
        IPrecogMarketV8 newMarket = IPrecogMarketV8(newMarketAddress);
        newMarket.initialize(md.collateral);

        // Get funding amount from funder to this contract (skipped if the collateralFunder is this contract)
        if (mc.collateralFunder != address(this)) {
            IERC20(md.collateral).safeTransferFrom(mc.collateralFunder, address(this), mc.collateralFunding);
        }
        // Pre approve all trades from this contract to the new Market contract
        IERC20(md.collateral).approve(newMarketAddress, type(uint256).max);

        // Calculate new market id and Setup deployed new market
        uint256 newId = createdMarkets;
        if (mc.liquidity == mc.collateralFunding) {
            // Setup a Full Liquidity market
            newMarket.setup(newId, mc.oracle, mc.totalOutcomes, mc.liquidity, mc.overround);
        } else {
            // Setup a Virtual Liquidity market
            newMarket.setupVL(newId, mc.oracle, mc.totalOutcomes, mc.liquidity, mc.overround, mc.collateralFunding);
        }
        newMarket.updateDates(md.startTimestamp, md.endTimestamp);
        if (mc.sellFeeFactor >= 0) newMarket.updateSellFeeFactor(uint256(mc.sellFeeFactor));

        // Save created market address and save it in local storage (indexed by market id)
        md.market = newMarketAddress;
        markets[newId] = md;

        // Increase created markets counter, emit event and return new market id
        createdMarkets = newId.add(1);
        emit MarketCreated(md.creator, md.operator, newId, newMarketAddress);
        return newId;
    }

    /**
     * @notice Withdraws available collateral from a closed market (initial funding + profits)
     * @dev Only the registered operator for the specific market can withdraw its collateral.
     * @param marketId Unique market identifier
     * @return amount Total collateral withdrawn (after protocol fee deduction, if applicable)
     */
    function withdrawMarketCollateral(uint256 marketId) external onlyMarketOperator returns (uint256 amount) {
        // Verify if the sender is the registered market operator of received market
        require(msg.sender == markets[marketId].operator, 'Not allowed operator');

        // Get amount available to be withdraw after all winning shares redeems (initial collateral + profit)
        IPrecogMarketV8 market = IPrecogMarketV8(markets[marketId].market);
        amount = market.withdrawAvailableCollateral(address(this));

        // Apply protocol fee (only some value was set)
        if (protocolFeeFactor > 0) {
            // Get market initial collateral amount
            (,,,,uint256 initialCollateral) = market.getMarketSetupInfo();

            // Verify if there is some market profit (protocol fee it's only applied on profitable markets)
            if (amount > initialCollateral) {
                uint256 marketProfit = amount.sub(initialCollateral);
                uint256 feeAmount = marketProfit.div(protocolFeeFactor);  // [protocolFee = 1 / protocolFeeFactor]
                // Re-calculate amount to transfer (after subtracting protocol fees)
                amount = amount.sub(feeAmount);
            }
        }

        // Transfer withdrawn collateral to operator
        IERC20(markets[marketId].collateral).safeTransfer(msg.sender, amount);
        return amount;
    }

    /**
     * @notice Buys shares on behalf of another account using Permit2 signature (operator-only)
     * @dev Allows market operators to execute trades for users via gasless Permit2 signatures.
     * @param account Address that will receive the purchased shares
     * @param marketId Unique market identifier
     * @param outcome Outcome index for which shares are being bought (e.g., 1=YES, 2=NO)
     * @param sharesAmount Number of shares to buy (64.64 fixed point)
     * @param maxAmountIn Max amount of collateral tokens willing to spend (slippage protection)
     * @param nonce Permit2 nonce to prevent signature replay
     * @param deadline Unix timestamp after which signature expires
     * @param sig Permit2 signature from the account authorizing the transfer
     * @return amountIn Actual collateral spent on the purchase
     */
    function buyMarketSharesFor(
        address account, uint256 marketId, uint256 outcome, int128 sharesAmount, uint256 maxAmountIn,
        uint256 nonce, uint256 deadline, bytes calldata sig
    ) external onlyMarketOperator returns (uint256 amountIn) {
        // Get market from received market id
        MarketData storage marketData = markets[marketId];

        // Verify if the sender is the registered market operator of received market
        require(msg.sender == marketData.operator, 'Not allowed operator');

        // Get maxAmountIn of tokens from the buyer to this contract with Permit2 signature
        address marketCollateral = marketData.collateral;
        _permit2TransferFrom(marketCollateral, account, address(this), maxAmountIn, nonce, deadline, sig);

        // Execute special BUY to market contract (to be assigned to the `account` and paid by the `operator`)
        amountIn = IPrecogMarketV8(marketData.market).buyFor(account, address(this), outcome, sharesAmount);
        require(amountIn <= maxAmountIn, "Buy cost too high");

        // If there is any leftover, return tokens to sender
        if (amountIn < maxAmountIn) {
            IERC20(marketCollateral).safeTransfer(account, maxAmountIn.sub(amountIn));
        }
        return amountIn;
    }

    /*//////////////////////////////////////////////////////////////
                        CALLER FUNCTIONS
           Privileged functions for whitelisted integrations.
    //////////////////////////////////////////////////////////////*/

    /** @notice Creates market without validations (trusted protocol callers) */
    function createCustomMarket(MarketData memory data, MarketConfig memory config) external onlyCaller
    returns (uint256 newMarketId) {
        return _createMarket(data, config);
    }

    /** @notice Withdraws market collateral to whitelisted receiver (trusted protocol callers) */
    function withdrawMarketCollateralTo(uint256 marketId, address to) external onlyCaller returns (uint256 amount) {
        require(allowedReceivers[to], 'Not allowed receiver');
        return IPrecogMarketV8(markets[marketId].market).withdrawAvailableCollateral(to);
    }

    /** @notice Buys shares for an account with separate payer (account gets shares, payer pays) */
    function buyMarketSharesForWithPayer(
        address account, address payer, uint256 marketId, uint256 outcome, int128 sharesAmount, uint256 maxAmountIn,
        uint256 nonce, uint256 deadline, bytes calldata sig
    ) external onlyCaller returns (uint256 amountIn) {
        // Get market from received market id
        MarketData storage marketData = markets[marketId];

        // Get maxAmountIn of tokens from the buyer to this contract with Permit2 signature
        address marketCollateral = marketData.collateral;
        _permit2TransferFrom(marketCollateral, payer, address(this), maxAmountIn, nonce, deadline, sig);

        // Execute special BUY to market contract (to be assigned to the `account` and paid by `payer`)
        amountIn = IPrecogMarketV8(marketData.market).buyFor(account, address(this), outcome, sharesAmount);
        require(amountIn <= maxAmountIn, "Buy cost too high");

        // If there is any leftover, return tokens to sender
        if (amountIn < maxAmountIn) {
            IERC20(marketCollateral).safeTransfer(payer, maxAmountIn.sub(amountIn));
        }
        return amountIn;
    }

    /*//////////////////////////////////////////////////////////////
                        ADMIN FUNCTIONS
    //////////////////////////////////////////////////////////////*/

    /** @notice Grants market operator role */
    function addMarketOperator(address account) external onlyAdmin {
        grantRole(MARKET_OPERATOR_ROLE, account);
    }

    /** @notice Revoke market operator role */
    function removeMarketOperator(address account) external onlyAdmin {
        revokeRole(MARKET_OPERATOR_ROLE, account);
    }

    /** @notice Grants caller role to an account */
    function addCaller(address account) external onlyAdmin {
        grantRole(CALLER_ROLE, account);
    }

    /** @notice Revokes caller role from an account */
    function removeCaller(address account) external onlyAdmin {
        revokeRole(CALLER_ROLE, account);
    }

    /** @notice Grants admin role to an account */
    function addAdmin(address account) external onlyAdmin {
        grantRole(ADMIN_ROLE, account);
    }

    /** @notice Revokes admin role from an account */
    function removeAdmin(address account) external onlyAdmin {
        revokeRole(ADMIN_ROLE, account);
    }

    /** @notice Registers a collateral token owned by this contract */
    function addOwnedCollateral(address collateral) external onlyAdmin {
        require(!ownedCollaterals[collateral]);
        require(IPrecogToken(collateral).owner() == address(this));
        ownedCollaterals[collateral] = true;
    }

    /** @notice Unregisters an owned collateral token */
    function removeOwnedCollateral(address collateral) external onlyAdmin {
        require(ownedCollaterals[collateral]);
        ownedCollaterals[collateral] = false;
    }

    /** @notice Whitelists an address to receive market collateral withdrawals */
    function addAllowedReceiver(address receiver) external onlyAdmin {
        require(!allowedReceivers[receiver]);
        allowedReceivers[receiver] = true;
    }

    /** @notice Removes an address from the allowed receivers whitelist */
    function removeAllowedReceiver(address receiver) external onlyAdmin {
        require(allowedReceivers[receiver]);
        allowedReceivers[receiver] = false;
    }

    /** @notice Whitelists an oracle for market creation */
    function addAllowedOracle(address oracle) external onlyAdmin {
        require(!allowedOracles[oracle]);
        allowedOracles[oracle] = true;
    }

    /** @notice Removes an oracle from the whitelist */
    function removeAllowedOracle(address oracle) external onlyAdmin {
        require(allowedOracles[oracle]);
        allowedOracles[oracle] = false;
    }

    /** @notice Whitelists a collateral token for market creation */
    function addAllowedCollateral(address collateral) external onlyAdmin {
        require(!allowedCollaterals[collateral]);
        allowedCollaterals[collateral] = true;
    }

    /** @notice Removes a collateral token from the whitelist */
    function removeAllowedCollateral(address collateral) external onlyAdmin {
        require(allowedCollaterals[collateral]);
        allowedCollaterals[collateral] = false;
    }

    /** @notice Sets the base market implementation for cloning */
    function setBaseMarket(address market) external onlyAdmin {
        baseMarket = market;

        // Initialize all market `lock` functions
        unlocked = 1;
    }

    /** @notice Sets the minimum overround required for market creation */
    function setMarketMinOverround(uint256 overround) external onlyAdmin {
        marketMinOverround = overround;
    }

    /** @notice Sets the minimum sell fee factor allowed for markets */
    function setMarketMinSellFeeFactor(int256 sellFeeFactor) external onlyAdmin {
        marketMinSellFeeFactor = sellFeeFactor;
    }

    /** @notice Sets the protocol fee factor (ProtocolFee = 1 / feeFactor) */
    function setProtocolFeeFactor(uint256 feeFactor) external onlyAdmin {
        protocolFeeFactor = feeFactor;
    }

    /**
     * @notice Updates market metadata and configuration (emergency use only)
     * @dev Pass empty strings or address(0) to skip updating specific fields
     */
    function updateMarket(
        uint256 id,
        string memory question,
        string memory resolutionCriteria,
        string memory imageURL,
        string memory category,
        string memory outcomes,
        address marketCreator,
        uint256 startTimestamp,
        uint256 endTimestamp,
        address marketOracle,
        int256 sellFeeFactor
    ) external onlyAdmin {
        // Get market from received id
        MarketData storage marketData = markets[id];

        // Validate received market implementation
        require(marketData.market != address(0), "Invalid market");

        // Verify and update market parameters on master
        if (bytes(question).length > 0) marketData.question = question;
        if (bytes(resolutionCriteria).length > 0) marketData.resolutionCriteria = resolutionCriteria;
        if (bytes(imageURL).length > 0) marketData.imageURL = imageURL;
        if (bytes(category).length > 0) marketData.category = category;
        if (bytes(outcomes).length > 0) marketData.outcomes = outcomes;
        if (marketCreator != address(0)) marketData.creator = marketCreator;

        // Verify and update market parameters on market instance
        if (marketOracle != address(0)) {
            IPrecogMarketV8(marketData.market).updateOracle(marketOracle);
        }
        if (sellFeeFactor >= 0) {
            IPrecogMarketV8(marketData.market).updateSellFeeFactor(uint256(sellFeeFactor));
        }
        bool updateDates = false;
        if (startTimestamp > 0) {
            marketData.startTimestamp = startTimestamp;
            updateDates = true;
        }
        if (endTimestamp > 0) {
            marketData.endTimestamp = endTimestamp;
            updateDates = true;
        }
        if (updateDates) {
            IPrecogMarketV8(marketData.market).updateDates(marketData.startTimestamp, marketData.endTimestamp);
        }
    }

    /** @notice Withdraws accidentally sent non-collateral tokens from a market contract */
    function marketWithdraw(uint256 marketId, address marketToken) external onlyAdmin {
        IPrecogMarketV8(markets[marketId].market).withdraw(marketToken);
    }

    /** @notice Transfers ownership of a market contract */
    function marketTransferOwnership(uint256 marketId, address newOwner) external onlyAdmin {
        IPrecogMarketV8(markets[marketId].market).transferOwnership(newOwner);
    }

    /** @notice Mints owned collateral tokens */
    function ownedTokenMint(address ownedToken, address to, uint256 amount) external onlyAdmin {
        IPrecogToken(ownedToken).mint(to, amount);
    }

    /** @notice Burns owned collateral tokens */
    function ownedTokenBurn(address ownedToken, address from, uint256 amount) external onlyAdmin {
        IPrecogToken(ownedToken).burn(from, amount);
    }

    /** @notice Moves owned collateral tokens between addresses */
    function ownedTokenMove(address ownedToken, address from, address to, uint256 amount) external onlyAdmin {
        IPrecogToken(ownedToken).move(from, to, amount);
    }

    /** @notice Transfers ownership of an owned collateral token */
    function ownedTokenTransferOwnership(address ownedToken, address newPrecogMaster) external onlyAdmin {
        IPrecogToken(ownedToken).transferOwnership(newPrecogMaster);
    }

    /** @notice Withdraws ETH or tokens from the Master contract */
    function withdraw(address _token) external onlyAdmin lock returns (uint256 amount) {
        if (_token == address(0)) {
            amount = address(this).balance;
            (bool ok,) = msg.sender.call{value: amount}("");
            require(ok);
        } else {
            amount = IERC20(_token).balanceOf(address(this));
            IERC20(_token).safeTransfer(msg.sender, amount);
        }
        return amount;
    }
}

contracts/PrecogOracleV1.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity 0.7.6;

import "@openzeppelin/contracts/math/SafeMath.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "./IPrecogMarket.sol";

/**
 * @title PrecogOracleV1: An smart oracle implementation to report results on Precog Markets
 * @author Marto (https://github.com/0xMarto)
 * @dev Feel free to make any adjustments to the code (DMs are open @0xMarto)
 */
contract PrecogOracleV1 is AccessControl {
    using SafeMath for uint256;
    using SafeERC20 for IERC20;

    // Constants
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant REPORTER_ROLE = keccak256("REPORTER_ROLE");

    // State objects
    struct MarketInfo {
        address market;       // Market contract address
        uint256 resultIndex;  // Market final result index (calculated computing all reported results)
        string resultLabel;   // Market final result label (calculated computing all reported results)
        uint256 minQuorum;    // Min amount of reports to calculate a final result
    }

    struct MarketReporter {
        bool allowed;         // Enabled if an account is allowed to report a result for the Market
        bool submitted;       // Enabled if an account already submit a result report for the Market
    }

    struct MarketReportedResult {
        string marketId;      // Market Id of the report
        address reporter;     // Reporter account
        uint256 outcomeIndex; // Index of the reported outcome
        string outcomeLabel;  // Label of the reported outcome
    }

    // Public variables
    address public precogMaster;
    mapping(uint256 => MarketInfo) public markets;
    mapping(uint256 => mapping(address => MarketReporter)) public marketReporters;
    mapping(uint256 => MarketReportedResult[]) public marketReportedResults;

    // Modifiers
    modifier onlyAdmin() {
        require(hasRole(ADMIN_ROLE, msg.sender), "Only Admin");
        _;
    }

    modifier onlyGlobalReporter() {
        require(hasRole(REPORTER_ROLE, msg.sender), "Only Reporter");
        _;
    }

    // Public Functions
    constructor(address initialAdmin) {
        // Grant DEFAULT_ADMIN_ROLE to the initial admin (this is the admin to the ADMIN_ROLE list)
        _setupRole(DEFAULT_ADMIN_ROLE, initialAdmin);

        // Set ADMIN_ROLE as admin of REPORTER_ROLE list
        _setRoleAdmin(REPORTER_ROLE, ADMIN_ROLE);

        // Grant ADMIN_ROLE to initial Admin (this enables to call "addAdmin" helper function)
        _setupRole(ADMIN_ROLE, initialAdmin);
    }

    function registerMarket(
        uint256 id, address market, uint256 minQuorum, address[] calldata initialReporters
    ) external onlyGlobalReporter {
        // Verify that the current was created by the current Precog Master
        require(IPrecogMarket(market).owner() == precogMaster, 'Invalid master');

        // Verify that the current oracle of the Market is this contract (to be able to report results)
        require(IPrecogMarket(market).oracle() == address(this), 'Invalid market');

        // Validate min quorum value
        require(minQuorum > 0, 'Invalid min quorum');

        // Allocate storage slot for the market
        markets[id] = MarketInfo(market, 0, '', minQuorum);

        // Register specific reporters for this market (only if the list is provided)
        if (initialReporters.length > 0) {
            for (uint256 i = 0; i < initialReporters.length; i++) {
                marketReporters[id][initialReporters[i]] = MarketReporter(true, false);
            }
        }
    }

    function submitReport(uint256 marketId, uint256 outcomeIndex, string calldata outcomeLabel) external {
        require(isMarketReporter(marketId, msg.sender), "Only Market Reporter");
        require(marketReporters[marketId][msg.sender].submitted, "Reporter already summited");
        require(outcomeIndex > 0, "Invalid Outcome Index");
        require(bytes(outcomeLabel).length > 0, "Invalid Outcome Label");

        // TODO Require that outcomeIndex > 0 and outcomeLabel != ''

        // TODO Implement this function

        // Register reporter submission
        marketReporters[marketId][msg.sender].submitted = true;
    }

    function calculateResult(uint256 marketId) external {
        // TODO Implement this function that set `resultIndex` and `resultLabel` of the received market
    }

    function reportResult(uint256 marketId) external {
        require(isMarketReporter(marketId, msg.sender), "Only Market Reporter");
        require(markets[marketId].resultIndex > 0, "Invalid Market");

        // Set market result on Market contract
        IPrecogMarket(markets[marketId].market).reportResult(
            marketId,
            markets[marketId].resultIndex
        );
    }

    /**
     * @notice Check if an account is allowed to summit/report result for a specific Market
     */
    function isMarketReporter(uint256 marketId, address account) public view returns (bool) {
        // Test the account is reporter for this specific market or is a global reporter
        return marketReporters[marketId][account].allowed || hasRole(REPORTER_ROLE, account);
    }

    /**
     * @notice Accept ETH for from any Transfer, Send or Call with value
     */
    receive() external payable {}

    // Whitelisted functions: Only admin
    function marketRedeemBatch(uint256 marketId, address[] calldata accounts) external onlyAdmin returns (uint256) {
        return IPrecogMarket(markets[marketId].market).redeemBatch(accounts);
    }

    function addMarketReporter(uint256 marketId, address account) external onlyAdmin {
        // Verify that the account is not already registered (to avoid reset 'submitted' flag)
        require(!marketReporters[marketId][account].allowed, 'Invalid reporter');

        // Register account as reporter for the received market id
        marketReporters[marketId][account] = MarketReporter(true, false);
    }

    function removeMarketReporter(uint256 marketId, address account) external onlyAdmin {
        // Verify that the account is already registered as reporter
        require(marketReporters[marketId][account].allowed, 'Invalid reporter');

        // Verify that the reporter did not already summit a result
        require(!marketReporters[marketId][account].submitted, 'Report already submitted');

        // Disable account as allowed reporter for the received market id
        marketReporters[marketId][account].allowed = false;
    }

    function addReporter(address account) external onlyAdmin {
        grantRole(REPORTER_ROLE, account);
    }

    function removeReporter(address account) external onlyAdmin {
        revokeRole(REPORTER_ROLE, account);
    }

    function setPrecogMaster(address master) external onlyAdmin {
        precogMaster = master;
    }

    function addAdmin(address account) external onlyAdmin {
        grantRole(ADMIN_ROLE, account);
    }

    function removeAdmin(address account) external onlyAdmin {
        revokeRole(ADMIN_ROLE, account);
    }

    function withdraw(address _token) public onlyAdmin {
        if (_token == address(0)) {
            payable(msg.sender).transfer(address(this).balance);
        } else {
            IERC20(_token).safeTransfer(msg.sender, IERC20(_token).balanceOf(address(this)));
        }
    }
}

contracts/PrecogRealityOracleV2.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity 0.7.6;
pragma abicoder v2;

import "@openzeppelin/contracts/math/SafeMath.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "./IPrecogMarket.sol";
import "./IRealityETH.sol";

/**
 * @title PrecogOracleRealityV1: An smart oracle implementation to report results on Precog Markets using Reality.eth
 * @author Marto (https://github.com/0xMarto) & Mati (https://github.com/0xAstraea)
 * @dev Feel free to make any adjustments to the code (DMs are open @0xMarto)
 */
contract PrecogRealityOracleV2 is AccessControl {
    using SafeMath for uint256;
    using SafeERC20 for IERC20;

    // Constants
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant REPORTER_ROLE = keccak256("REPORTER_ROLE");

    // State objects
    struct MarketInfo {
        address market;       // Market contract address
        bytes32 questionId;   // Question Identifier on Reality.eth contract
        string outcomes;      // CSV of valid outcomes labels
        bool answered;        // Flag that signal that a answer was submitted to Reality.eth
        uint256 resultIndex;  // Market final result index (calculated computing all reported results)
        string resultLabel;   // Market final result label (calculated computing all reported results)
    }

    // Public variables
    address public precogMaster;
    address public reality;
    address public arbitrator;
    uint256 public maxAnswerBond;
    mapping(uint256 => MarketInfo) public markets;
    mapping(uint256 => mapping(address => bool)) public marketReporters;

    // Modifiers
    modifier onlyAdmin() {
        require(hasRole(ADMIN_ROLE, msg.sender), "Only Admin");
        _;
    }

    modifier onlyGlobalReporter() {
        require(hasRole(REPORTER_ROLE, msg.sender), "Only Reporter");
        _;
    }

    modifier onlyMarketReporter(uint256 marketId) {
        require(isMarketReporter(marketId, msg.sender), "Only Market Reporter");
        _;
    }

    /**
     * @notice Initializes the PrecogRealityOracleV1 contract
	 * @param initialAdmin Address that will be granted the first Admin account
	 */
    constructor(address initialAdmin) {
        // Grant DEFAULT_ADMIN_ROLE to the initial admin (this is the admin to the ADMIN_ROLE list)
        _setupRole(DEFAULT_ADMIN_ROLE, initialAdmin);

        // Set ADMIN_ROLE as admin of REPORTER_ROLE list
        _setRoleAdmin(REPORTER_ROLE, ADMIN_ROLE);

        // Grant ADMIN_ROLE to initial Admin (this enables to call "addAdmin" helper function)
        _setupRole(ADMIN_ROLE, initialAdmin);
    }

    /**
     * @notice Registers a new market with this oracle
	 * @dev Validates market ownership and oracle assignment before registration
	 *      Requirements:
	 *      - Caller must have REPORTER_ROLE
	 *      - Market must be owned by precogMaster
	 *      - Market must have this contract set as its oracle
	 *      - Market ID must not be already registered
	 * @param id Unique identifier for the market
	 * @param market Address of the PrecogMarket contract
	 * @param initialReporters Optional array of addresses that can report for this specific market
	 */
    function registerMarket(
        uint256 id,
        address market,
        address[] calldata initialReporters
    ) external onlyGlobalReporter {
        // Verify that the current was created by the current Precog Master
        require(IPrecogMarket(market).owner() == precogMaster, "Invalid master");

        // Verify that the current oracle of the Market is this contract (to be able to report results)
        require(IPrecogMarket(market).oracle() == address(this), "Invalid market");

        // Verify that the received market id is not already registered
        require(markets[id].market == address(0), "Already register market");

        // Allocate storage slot for the market
        markets[id] = MarketInfo(market, bytes32(0), "", false, 0, "");

        // Register specific reporters for this market (only if the list is provided)
        if (initialReporters.length > 0) {
            for (uint256 i = 0; i < initialReporters.length; i++) {
                marketReporters[id][initialReporters[i]] = true;
            }
        }
    }

    /**
     * @notice Opens a new question in Reality.eth for a specific market
	 * @dev This function require that the sender `isMarketReporter`
	 * @param marketId The market this question belongs to
	 * @param bounty Amount of ETH to offer as question bounty
	 * @param templateId Reality.eth template ID defining question structure
	 * @param question The actual question text
	 * @param outcomes Array of possible answer options
	 * @param category Question category for organization
	 * @param timeout Duration in seconds before question can be answered
	 * @param startTime Timestamp when question becomes answerable
	 * @return questionId Unique identifier of the created question in Reality.eth
	 */
    function openQuestion(
        uint256 marketId,
        uint256 bounty,
        uint32 templateId,
        string calldata question,
        string[] calldata outcomes,
        string calldata category,
        uint32 timeout,
        uint32 startTime
    ) public payable onlyMarketReporter(marketId) returns (bytes32 questionId) {
        // Verify that the market is already registered
        require(isMarketRegistered(marketId), "Market not registered");

        // Verify market is already registered
        require(markets[marketId].questionId == bytes32(0), "Question already open");

        // Open a question in Reality.eth
        questionId = IRealityETH(reality).askQuestion{value: bounty}(
            templateId,
            _formatQuestion(question, outcomes, category),
            arbitrator,
            timeout,
            startTime,
            0 // Fixed nonce (as is not needed as unique identifier)
        );

        // Save the questionId and outcomes to the market
        markets[marketId].questionId = questionId;
        markets[marketId].outcomes = _arrayToCSV(outcomes);

        // Return new question id
        return questionId;
    }

    /**
     * @notice Submits an answer to an open Reality.eth question for a market
	 * @dev This function require that the sender `isMarketReporter`
	 * @param marketId The market whose question is being answered
	 * @param answer The answer being submitted (as bytes32)
	 * @param maxPrevious Maximum previous bond to calculate minimum new bond
	 * @param bond Amount of ETH to bond with this answer
	 */
    function answerOpenQuestion(
        uint256 marketId,
        bytes32 answer,
        uint256 maxPrevious,
        uint256 bond
    ) public payable onlyMarketReporter(marketId) {
        // Verify that the market is already registered
        require(isMarketRegistered(marketId), "Market not registered");

        // Get and check question id for received market
        bytes32 questionId = markets[marketId].questionId;
        require(questionId != bytes32(0), "Market Id not found");

        // Verify that this market do not have an answer
        require(!markets[marketId].answered, "Market already answered");

        // Verify than received bond is not higher than expected
        require(bond <= maxAnswerBond, "Answer bond too high");

        // Submit an answer in name of another address in Reality.eth
        IRealityETH(reality).submitAnswer{value: bond}(
            questionId,
            answer,
            maxPrevious
        );

        // Register answer on Market
        markets[marketId].answered = true;
    }

    /**
     * @notice Submit a Market result by opening question and answering it (to be disputed or validate it)
	 * @dev This function require that the sender `isMarketReporter`
	 * @return questionId The unique identifier for the question
	 */
    function submitResult(
        uint256 marketId,
        uint32 templateId,
        string calldata question,
        string[] calldata outcomes,
        string calldata category,
        uint32 timeout,
        uint32 startTime,
        bytes32 answer,
        uint256 bond
    ) external payable onlyMarketReporter(marketId) returns (bytes32 questionId) {
        // Open a question in Reality.eth with custom question text
        questionId = openQuestion(
            marketId,
            0,  // Question Bounty = 0, fixed because we send `bond` in the first answer
            templateId,
            question,
            outcomes,
            category,
            timeout,
            startTime
        );

        // Submit answer with the remaining value (after bounty is spent)
        answerOpenQuestion(
            marketId,
            answer,
            0, // MaxPrevious Bond = 0, fixed because it is the first answer
            bond // Answer Bond (the remainder of the tx value)
        );

        return questionId;
    }

    /**
     * @notice Report result validated by Reality.eth to corresponding Market
     * @dev Also store validated result in local storage to be audited
	 */
    function reportResult(uint256 marketId) external onlyGlobalReporter {
        bytes32 questionId = markets[marketId].questionId;
        require(questionId != bytes32(0), "Market Id not found");

        // Verify that the question for the received market is finalized on Reality.eth
        require(IRealityETH(reality).isFinalized(questionId), "Invalid question");

        // Verify that the market is not already being reported
        require(markets[marketId].resultIndex == 0, "Market already reported");

        bytes32 answer = IRealityETH(reality).getBestAnswer(questionId);
        uint256 answerIndex = uint256(answer); // This is the Reality.eth 0-based index result

        // Get the label for this index from the outcomes
        string[] memory outcomes = _csvToArray(markets[marketId].outcomes);

        require(answerIndex < outcomes.length, "Invalid answer");
        string memory resultLabel = outcomes[answerIndex];

        // The PrecogMarket contract expects a 1-based index for the result
        uint256 resultIndex = answerIndex + 1;

        // Set market result on PrecogMarket external contract
        IPrecogMarket(markets[marketId].market).reportResult(marketId, resultIndex);

        // Set result index and label on local Market
        markets[marketId].resultIndex = resultIndex;
        markets[marketId].resultLabel = resultLabel;
    }

    /**
     * @notice Open a question in Reality.eth without a local register market
	 * @return questionId The unique identifier for the question
	 */
    function realityOpenQuestion(
        uint256 bounty,
        uint32 templateId,
        string calldata question,
        string[] calldata outcomes,
        string calldata category,
        uint32 timeout,
        uint32 startTime,
        uint32 nonce
    ) public payable onlyGlobalReporter returns (bytes32 questionId) {
        // Build the formatted question (internal helper will allocate memory)
        string memory formattedQuestion = _formatQuestion(question, outcomes, category);

        questionId = IRealityETH(reality).askQuestion{value: bounty}(
            templateId,
            formattedQuestion,
            arbitrator,
            timeout,
            startTime,
            nonce
        );

        return questionId;
    }

    /**
     * @notice Submit an answer in name of another address in Reality.eth
	 * @param questionId The question Id to answer
	 * @param answer The answer to submit
	 * @param maxPrevious Maximum number of previous answers to consider
	 * @param answerer The address submitting the answer for
	 */
    function realitySubmitAnswerFor(
        uint256 bond,
        bytes32 questionId,
        bytes32 answer,
        uint256 maxPrevious,
        address answerer
    ) public payable onlyGlobalReporter {
        IRealityETH(reality).submitAnswerFor{value: bond}(
            questionId,
            answer,
            maxPrevious,
            answerer
        );
    }

    /**
     * @notice Assign winnings in Reality.eth of a question, to later claim them by the answerer
	 * @param questionId The question Id to claim winnings for
	 * @param historyHashes The history hashes for the claim
	 * @param answerers The addresses involved in the claim
	 * @param bonds The bonds for the claim
	 * @param answers The answers for the claim
	 */
    function realityClaimWinnings(
        bytes32 questionId,
        bytes32[] calldata historyHashes,
        address[] calldata answerers,
        uint256[] calldata bonds,
        bytes32[] calldata answers
    ) external onlyGlobalReporter {
        IRealityETH(reality).claimWinnings(
            questionId,
            historyHashes,
            answerers,
            bonds,
            answers
        );
    }

    /**
     * @notice Executes a withdraw on Reality.eth contract
	 */
    function realityWithdraw() external onlyGlobalReporter {
        IRealityETH(reality).withdraw();
    }

    function marketRedeemBatch(
        uint256 marketId,
        address[] calldata accounts
    ) external onlyGlobalReporter returns (uint256) {
        return IPrecogMarket(markets[marketId].market).redeemBatch(accounts);
    }

    /**
     * @notice Check if a market is already registered on this oracle
	 */
    function isMarketRegistered(uint256 marketId) public view returns (bool) {
        return markets[marketId].market != address(0);
    }

    /**
     * @notice Check if an account is allowed to summit/report result for a specific Market
	 */
    function isMarketReporter(
        uint256 marketId,
        address account
    ) public view returns (bool) {
        // Test the account is reporter for this specific market or is a global reporter
        return marketReporters[marketId][account] || hasRole(REPORTER_ROLE, account);
    }

    /**
     * @notice Returns the permissions status of a given account.
     * @param account The address of the account to check.
     * @return isAdmin Indicates whether the account has the admin role.
     * @return isGlobalReporter Indicates whether the account has the reporter role.
     */
    function getAccountPermissions(address account) external view returns (bool isAdmin, bool isGlobalReporter) {
        isAdmin = hasRole(ADMIN_ROLE, account);
        isGlobalReporter = hasRole(REPORTER_ROLE, account);
        return (isAdmin, isGlobalReporter);
    }

    /**
     * @notice Returns the current state of a given market.
     * @param marketId The market Id to get the current state parameters
     * @return isRegistered Indicates whether the market is registered in the system.
     * @return isAnswered Indicates whether the market has been answered by a reporter.
     * @return isFinalized Indicates whether the market answer is final and the result can be reported.
     * @return isReported Indicates whether the market's result has been reported.
     */
    function getMarketState(uint256 marketId) external view returns (
        bool isRegistered,
        bool isAnswered,
        bool isFinalized,
        bool isReported
    ) {
        // Calculate market states for the received market id
        isRegistered = markets[marketId].market != address(0);
        isAnswered = markets[marketId].answered;
        isFinalized = IRealityETH(reality).isFinalized(markets[marketId].questionId);
        isReported = markets[marketId].resultIndex > 0;
        return (isRegistered, isAnswered, isFinalized, isReported);
    }

    /**
     * @notice Get the Reality.eth balance of this contract
	 */
    function getRealityBalance() external view returns (uint256) {
        return IRealityETH(reality).balanceOf(address(this));
    }

    /**
     * @notice Get comprehensive information about a Reality Question starting settings
	 * @param marketId The market Id to get information for
	 */
    function getRealityQuestionInfo(uint256 marketId) external view returns (
        bytes32 questionId, uint32 openingTS, uint32 timeout, uint256 bounty, uint256 bond
    ) {
        // Get Reality question id for received market
        questionId = markets[marketId].questionId;

        // Validate existence of received market
        require(questionId != bytes32(0), "Market Id not found");

        // Instance Reality contract and get all needed info
        IRealityETH realityEth = IRealityETH(reality);
        openingTS = realityEth.getOpeningTS(questionId);
        timeout = realityEth.getTimeout(questionId);
        bounty = realityEth.getBounty(questionId);
        bond = realityEth.getBond(questionId);

        // Return Reality info about received market id
        return (questionId, openingTS, timeout, bounty, bond);
    }

    /**
     * @notice Get information about a Question resolution status
	 * @param marketId The Market Id  to get Reality result info
	 * @return questionId question identifier
	 * @return answer the current last or final answer value (as bytes32 index)
	 * @return finalizeTS The pending time to reach the answer timeout
	 * @return lastHash The history hash of the last answer
	 * @return isFinalized Whether the question is finalized
	 * @return isPendingArbitration Whether the question is pending arbitration
	 */
    function getRealityResultInfo(uint256 marketId) external view returns (
        bytes32 questionId,
        bytes32 answer,
        uint32 finalizeTS,
        bytes32 lastHash,
        bool isFinalized,
        bool isPendingArbitration
    ) {
        // Get Reality question id for received market
        questionId = markets[marketId].questionId;

        // Validate existence of received market
        require(questionId != bytes32(0), "Market Id not found");

        IRealityETH realityEth = IRealityETH(reality);
        answer = realityEth.getBestAnswer(questionId);
        finalizeTS = realityEth.getFinalizeTS(questionId);
        lastHash = realityEth.getHistoryHash(questionId);
        isFinalized = realityEth.isFinalized(questionId);
        isPendingArbitration = realityEth.isPendingArbitration(questionId);

        return (questionId, answer, finalizeTS, lastHash, isFinalized, isPendingArbitration);
    }

    /**
     * @notice Internal helper function that formats a question string according to Reality.eth specifications
	 * @dev Combines question text, outcomes, and category using the Reality.eth separator '␟'
	 * @param question The main question text to be asked
	 * @param outcomes Array of possible answer options that will be presented to users
	 * @param category The classification category for the question
	 * @return formatedQuestion A output string in the format: "question␟['outcome1','outcome2',...]␟category␟"
	 */
    function _formatQuestion(
        string calldata question,
        string[] calldata outcomes,
        string calldata category
    ) internal pure returns (string memory formatedQuestion) {
        // Build outcome CSV string
        bytes memory outcomesBytes = bytes("");
        if (outcomes.length > 0) {
            outcomesBytes = abi.encodePacked('"', outcomes[0], '"');
            for (uint256 i = 1; i < outcomes.length; i++) {
                outcomesBytes = abi.encodePacked(outcomesBytes, ',"', outcomes[i], '"');
            }
        }
        // Build question string based on Reality custom format
        formatedQuestion = string(
            abi.encodePacked(question, unicode"␟", string(outcomesBytes), unicode"␟", category, unicode"␟")
        );
        return formatedQuestion;
    }

    /**
     * @notice Converts an array of strings into a comma-separated string
	 * @dev Example: ["Yes", "No", "Maybe"] => "Yes,No,Maybe"
	 * @param array The array of strings to join
	 * @return A single string with all elements joined by commas, or empty string if array is empty
	 */
    function _arrayToCSV(string[] memory array) internal pure returns (string memory) {
        if (array.length == 0) {
            return "";
        }

        bytes memory csvBytes = bytes(array[0]);
        for (uint i = 1; i < array.length; i++) {
            csvBytes = abi.encodePacked(csvBytes, ",", array[i]);
        }
        return string(csvBytes);
    }

    /**
     * @notice Splits a comma-separated string into an array of individual strings
	 * @dev Example: "Yes,No,Maybe" => ["Yes", "No", "Maybe"]
	 * @param csv The comma-separated string to split
	 * @return An array of individual strings, or empty array if input is empty
	 */
    function _csvToArray(string memory csv) internal pure returns (string[] memory) {
        bytes memory csvBytes = bytes(csv);
        if (csvBytes.length == 0) {
            return new string[](0);
        }

        // 1. Count how many elements we have
        uint256 count = 1;
        for (uint256 i = 0; i < csvBytes.length; i++) {
            if (csvBytes[i] == ",") {
                count++;
            }
        }

        // 2. Create the array and populate it
        string[] memory result = new string[](count);
        uint256 resultIndex = 0;
        uint256 startIndex = 0;

        for (uint256 i = 0; i < csvBytes.length; i++) {
            if (csvBytes[i] == ",") {
                result[resultIndex] = _substring(csvBytes, startIndex, i);
                resultIndex++;
                startIndex = i + 1;
            }
        }

        // Add the last element
        result[resultIndex] = _substring(csvBytes, startIndex, csvBytes.length);

        return result;
    }

    /**
     * @notice Extracts a portion of a bytes array into a new string
	 * @dev Helper function for _csvToArray to extract individual elements
	 * @param source The source bytes array to extract from
	 * @param start The starting index (inclusive) in the source array
	 * @param end The ending index (exclusive) in the source array
	 * @return A new string containing the extracted bytes
	 */
    function _substring(bytes memory source, uint256 start, uint256 end) internal pure returns (string memory) {
        uint256 len = end - start;
        bytes memory dest = new bytes(len);
        for (uint256 i = 0; i < len; i++) {
            dest[i] = source[start + i];
        }
        return string(dest);
    }

    /**
     * @notice Accept ETH for from any Transfer, Send or Call with value
	 */
    receive() external payable {}

    // Whitelisted functions: Only admin
    function setPrecogMaster(address master) external onlyAdmin {
        precogMaster = master;
    }

    function setReality(address realityProxy) external onlyAdmin {
        reality = realityProxy;
    }

    function setArbitrator(address arbitratorProxy) external onlyAdmin {
        arbitrator = arbitratorProxy;
    }

    function setMaxAnswerBond(uint256 maxBond) external onlyAdmin {
        maxAnswerBond = maxBond;
    }

    function addMarketReporter(
        uint256 marketId,
        address account
    ) external onlyAdmin {
        // Verify that the account is not already registered (to avoid reset 'submitted' flag)
        require(!marketReporters[marketId][account], "Invalid reporter");

        // Register account as reporter for the received market id
        marketReporters[marketId][account] = true;
    }

    function removeMarketReporter(
        uint256 marketId,
        address account
    ) external onlyAdmin {
        // Verify that the account is already registered as reporter
        require(marketReporters[marketId][account], "Invalid reporter");

        // Disable account as allowed reporter for the received market id
        marketReporters[marketId][account] = false;
    }

    function addReporter(address account) external onlyAdmin {
        grantRole(REPORTER_ROLE, account);
    }

    function removeReporter(address account) external onlyAdmin {
        revokeRole(REPORTER_ROLE, account);
    }

    function addAdmin(address account) external onlyAdmin {
        grantRole(ADMIN_ROLE, account);
    }

    function removeAdmin(address account) external onlyAdmin {
        revokeRole(ADMIN_ROLE, account);
    }

    function withdraw(address _token) public onlyAdmin {
        if (_token == address(0)) {
            payable(msg.sender).transfer(address(this).balance);
        } else {
            IERC20(_token).safeTransfer(
                msg.sender,
                IERC20(_token).balanceOf(address(this))
            );
        }
    }
}

contracts/PrecogRealityOracleV3.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity 0.7.6;
pragma abicoder v2;

import "@openzeppelin/contracts/math/SafeMath.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "./IPrecogMarketV8.sol";
import "./IRealityETH.sol";

/**
 * @title PrecogOracleRealityV3: An smart oracle implementation to report results on Precog Markets using Reality.eth
 * @author Marto (https://github.com/0xMarto) & Mati (https://github.com/0xAstraea)
 * @dev Feel free to make any adjustments to the code (DMs are open @0xMarto)
 */
contract PrecogRealityOracleV3 is AccessControl {
    using SafeMath for uint256;
    using SafeERC20 for IERC20;

    // Constants
    bytes32 public constant ADMIN_ROLE = keccak256("ADMIN_ROLE");
    bytes32 public constant REPORTER_ROLE = keccak256("REPORTER_ROLE");

    // State objects
    struct MarketInfo {
        address market;       // Market contract address
        bytes32 questionId;   // Question Identifier on Reality.eth contract
        string outcomes;      // CSV of valid outcomes labels
        bool answered;        // Flag that signal that a answer was submitted to Reality.eth
        uint256 resultIndex;  // Market final result index (calculated computing all reported results)
        string resultLabel;   // Market final result label (calculated computing all reported results)
    }

    // Public variables
    address public precogMaster;
    address public reality;
    address public arbitrator;
    uint256 public maxAnswerBond;
    mapping(uint256 => MarketInfo) public markets;
    mapping(uint256 => mapping(address => bool)) public marketReporters;

    // Modifiers
    modifier onlyAdmin() {
        require(hasRole(ADMIN_ROLE, msg.sender), "Only Admin");
        _;
    }

    modifier onlyGlobalReporter() {
        require(hasRole(REPORTER_ROLE, msg.sender), "Only Reporter");
        _;
    }

    modifier onlyMarketReporter(uint256 marketId) {
        require(isMarketReporter(marketId, msg.sender), "Only Market Reporter");
        _;
    }

    /**
     * @notice Initializes the PrecogRealityOracleV1 contract
	 * @param initialAdmin Address that will be granted the first Admin account
	 */
    constructor(address initialAdmin) {
        // Grant DEFAULT_ADMIN_ROLE to the initial admin (this is the admin to the ADMIN_ROLE list)
        _setupRole(DEFAULT_ADMIN_ROLE, initialAdmin);

        // Set ADMIN_ROLE as admin of REPORTER_ROLE list
        _setRoleAdmin(REPORTER_ROLE, ADMIN_ROLE);

        // Grant ADMIN_ROLE to initial Admin (this enables to call "addAdmin" helper function)
        _setupRole(ADMIN_ROLE, initialAdmin);
    }

    /**
     * @notice Registers a new market with this oracle
	 * @dev Validates market ownership and oracle assignment before registration
	 *      Requirements:
	 *      - Caller must have REPORTER_ROLE
	 *      - Market must be owned by precogMaster
	 *      - Market must have this contract set as its oracle
	 *      - Market ID must not be already registered
	 * @param id Unique identifier for the market
	 * @param market Address of the PrecogMarket contract
	 * @param initialReporters Optional array of addresses that can report for this specific market
	 */
    function registerMarket(
        uint256 id,
        address market,
        address[] calldata initialReporters
    ) external onlyGlobalReporter {
        // Verify that the current was created by the current Precog Master
        require(IPrecogMarketV8(market).owner() == precogMaster, "Invalid master");

        // Verify that the current oracle of the Market is this contract (to be able to report results)
        require(IPrecogMarketV8(market).oracle() == address(this), "Invalid market");

        // Verify that the received market id is not already registered
        require(markets[id].market == address(0), "Already register market");

        // Allocate storage slot for the market
        markets[id] = MarketInfo(
            market,
            bytes32(0),
            "",
            false,
            0,
            ""
        );

        // Register specific reporters for this market (only if the list is provided)
        if (initialReporters.length > 0) {
            for (uint256 i = 0; i < initialReporters.length; i++) {
                marketReporters[id][initialReporters[i]] = true;
            }
        }
    }

    /**
     * @notice Opens a new question in Reality.eth for a specific market
	 * @dev This function require that the sender `isMarketReporter`
	 * @param marketId The market this question belongs to
	 * @param bounty Amount of ETH to offer as question bounty
	 * @param templateId Reality.eth template ID defining question structure
	 * @param question The actual question text
	 * @param outcomes Array of possible answer options
	 * @param category Question category for organization
	 * @param timeout Duration in seconds before question can be answered
	 * @param startTime Timestamp when question becomes answerable
	 * @return questionId Unique identifier of the created question in Reality.eth
	 */
    function openQuestion(
        uint256 marketId,
        uint256 bounty,
        uint32 templateId,
        string calldata question,
        string[] calldata outcomes,
        string calldata category,
        uint32 timeout,
        uint32 startTime
    ) public payable onlyMarketReporter(marketId) returns (bytes32 questionId) {
        // Verify that the market is already registered
        require(isMarketRegistered(marketId), "Market not registered");

        // Verify market is already registered
        require(markets[marketId].questionId == bytes32(0), "Question already open");

        // Open a question in Reality.eth
        questionId = IRealityETH(reality).askQuestion{value: bounty}(
            templateId,
            _formatQuestion(question, outcomes, category),
            arbitrator,
            timeout,
            startTime,
            0 // Fixed nonce (as is not needed as unique identifier)
        );

        // Save the questionId and outcomes to the market
        markets[marketId].questionId = questionId;
        markets[marketId].outcomes = _arrayToCSV(outcomes);

        // Return new question id
        return questionId;
    }

    /**
     * @notice Submits an answer to an open Reality.eth question for a market
	 * @dev This function require that the sender `isMarketReporter`
	 * @param marketId The market whose question is being answered
	 * @param answer The answer being submitted (as bytes32)
	 * @param maxPrevious Maximum previous bond to calculate minimum new bond
	 * @param bond Amount of ETH to bond with this answer
	 */
    function answerOpenQuestion(
        uint256 marketId,
        bytes32 answer,
        uint256 maxPrevious,
        uint256 bond
    ) public payable onlyMarketReporter(marketId) {
        // Verify that the market is already registered
        require(isMarketRegistered(marketId), "Market not registered");

        // Get and check question id for received market
        bytes32 questionId = markets[marketId].questionId;
        require(questionId != bytes32(0), "Market Id not found");

        // Verify that this market do not have an answer
        require(!markets[marketId].answered, "Market already answered");

        // Verify than received bond is not higher than expected
        require(bond <= maxAnswerBond, "Answer bond too high");

        // Submit an answer in name of another address in Reality.eth
        IRealityETH(reality).submitAnswer{value: bond}(
            questionId,
            answer,
            maxPrevious
        );

        // Register answer on Market
        markets[marketId].answered = true;
    }

    /**
     * @notice Submit a Market result by opening question and answering it (to be disputed or validate it)
	 * @dev This function require that the sender `isMarketReporter`
	 * @return questionId The unique identifier for the question
	 */
    function submitResult(
        uint256 marketId,
        uint32 templateId,
        string calldata question,
        string[] calldata outcomes,
        string calldata category,
        uint32 timeout,
        uint32 startTime,
        bytes32 answer,
        uint256 bond
    ) external payable onlyMarketReporter(marketId) returns (bytes32 questionId) {
        // Open a question in Reality.eth with custom question text
        questionId = openQuestion(
            marketId,
            0,  // Question Bounty = 0, fixed because we send `bond` in the first answer
            templateId,
            question,
            outcomes,
            category,
            timeout,
            startTime
        );

        // Submit answer with the remaining value (after bounty is spent)
        answerOpenQuestion(
            marketId,
            answer,
            0, // MaxPrevious Bond = 0, fixed because it is the first answer
            bond // Answer Bond (the remainder of the tx value)
        );

        return questionId;
    }

    /**
     * @notice Report result validated by Reality.eth to corresponding Market
     * @dev Also store validated result in local storage to be audited
	 */
    function reportResult(uint256 marketId) external onlyGlobalReporter {
        bytes32 questionId = markets[marketId].questionId;
        require(questionId != bytes32(0), "Market Id not found");

        // Verify that the question for the received market is finalized on Reality.eth
        require(IRealityETH(reality).isFinalized(questionId), "Invalid question");

        // Verify that the market is not already being reported
        require(markets[marketId].resultIndex == 0, "Market already reported");

        bytes32 answer = IRealityETH(reality).getBestAnswer(questionId);
        uint256 answerIndex = uint256(answer); // This is the Reality.eth 0-based index result

        // Get the label for this index from the outcomes
        string[] memory outcomes = _csvToArray(markets[marketId].outcomes);

        require(answerIndex < outcomes.length, "Invalid answer");
        string memory resultLabel = outcomes[answerIndex];

        // The PrecogMarket contract expects a 1-based index for the result
        uint256 resultIndex = answerIndex + 1;

        // Set market result on PrecogMarket external contract
        IPrecogMarketV8(markets[marketId].market).reportResult(marketId, resultIndex);

        // Set result index and label on local Market
        markets[marketId].resultIndex = resultIndex;
        markets[marketId].resultLabel = resultLabel;
    }

    /**
     * @notice Open a question in Reality.eth without a local register market
	 * @return questionId The unique identifier for the question
	 */
    function realityOpenQuestion(
        uint256 bounty,
        uint32 templateId,
        string calldata question,
        string[] calldata outcomes,
        string calldata category,
        uint32 timeout,
        uint32 startTime,
        uint256 nonce,
        uint256 minBond
    ) public payable onlyGlobalReporter returns (bytes32 questionId) {
        // Build the formatted question (internal helper will allocate memory)
        string memory formattedQuestion = _formatQuestion(question, outcomes, category);

        questionId = IRealityETH(reality).askQuestionWithMinBond{value: bounty}(
            templateId,
            formattedQuestion,
            arbitrator,
            timeout,
            startTime,
            nonce,
            minBond
        );

        return questionId;
    }

    /**
     * @notice Submit an answer in name of another address in Reality.eth
	 * @param questionId The question Id to answer
	 * @param answer The answer to submit
	 * @param maxPrevious Maximum number of previous answers to consider
	 * @param answerer The address submitting the answer for
	 */
    function realitySubmitAnswerFor(
        uint256 bond,
        bytes32 questionId,
        bytes32 answer,
        uint256 maxPrevious,
        address answerer
    ) public payable onlyGlobalReporter {
        IRealityETH(reality).submitAnswerFor{value: bond}(
            questionId,
            answer,
            maxPrevious,
            answerer
        );
    }

    /**
     * @notice Assign winnings in Reality.eth of a question, to later claim them by the answerer
	 * @param questionId The question Id to claim winnings for
	 * @param historyHashes The history hashes for the claim
	 * @param answerers The addresses involved in the claim
	 * @param bonds The bonds for the claim
	 * @param answers The answers for the claim
	 */
    function realityClaimWinnings(
        bytes32 questionId,
        bytes32[] calldata historyHashes,
        address[] calldata answerers,
        uint256[] calldata bonds,
        bytes32[] calldata answers
    ) external onlyGlobalReporter {
        IRealityETH(reality).claimWinnings(
            questionId,
            historyHashes,
            answerers,
            bonds,
            answers
        );
    }

    /**
     * @notice Executes a withdraw on Reality.eth contract
	 */
    function realityWithdraw() external onlyGlobalReporter {
        IRealityETH(reality).withdraw();
    }

    function marketRedeemBatch(
        uint256 marketId,
        address[] calldata accounts
    ) external onlyGlobalReporter returns (uint256) {
        return IPrecogMarketV8(markets[marketId].market).redeemBatch(accounts);
    }

    function marketEnableDatesUpdate(uint256 marketId) external onlyGlobalReporter {
        IPrecogMarketV8(markets[marketId].market).enableDatesUpdate(marketId);
    }

    /**
     * @notice Check if a market is already registered on this oracle
	 */
    function isMarketRegistered(uint256 marketId) public view returns (bool) {
        return markets[marketId].market != address(0);
    }

    /**
     * @notice Check if an account is allowed to summit/report result for a specific Market
	 */
    function isMarketReporter(
        uint256 marketId,
        address account
    ) public view returns (bool) {
        // Test the account is reporter for this specific market or is a global reporter
        return marketReporters[marketId][account] || hasRole(REPORTER_ROLE, account);
    }

    /**
     * @notice Returns the permissions status of a given account.
     * @param account The address of the account to check.
     * @return isAdmin Indicates whether the account has the admin role.
     * @return isGlobalReporter Indicates whether the account has the reporter role.
     */
    function getAccountPermissions(address account) external view returns (bool isAdmin, bool isGlobalReporter) {
        isAdmin = hasRole(ADMIN_ROLE, account);
        isGlobalReporter = hasRole(REPORTER_ROLE, account);
        return (isAdmin, isGlobalReporter);
    }

    /**
     * @notice Returns the current state of a given market.
     * @param marketId The market Id to get the current state parameters
     * @return isRegistered Indicates whether the market is registered in the system.
     * @return isAnswered Indicates whether the market has been answered by a reporter.
     * @return isFinalized Indicates whether the market answer is final and the result can be reported.
     * @return isReported Indicates whether the market's result has been reported.
     */
    function getMarketState(uint256 marketId) external view returns (
        bool isRegistered,
        bool isAnswered,
        bool isFinalized,
        bool isReported
    ) {
        // Calculate market states for the received market id
        isRegistered = markets[marketId].market != address(0);
        isAnswered = markets[marketId].answered;
        isFinalized = IRealityETH(reality).isFinalized(markets[marketId].questionId);
        isReported = markets[marketId].resultIndex > 0;
        return (isRegistered, isAnswered, isFinalized, isReported);
    }

    /**
     * @notice Get the Reality.eth balance of this contract
	 */
    function getRealityBalance() external view returns (uint256) {
        return IRealityETH(reality).balanceOf(address(this));
    }

    /**
     * @notice Get comprehensive information about a Reality Question starting settings
	 * @param marketId The market Id to get information for
	 */
    function getRealityQuestionInfo(uint256 marketId) external view returns (
        bytes32 questionId, uint32 openingTS, uint32 timeout, uint256 bounty, uint256 bond
    ) {
        // Get Reality question id for received market
        questionId = markets[marketId].questionId;

        // Validate existence of received market
        require(questionId != bytes32(0), "Market Id not found");

        // Instance Reality contract and get all needed info
        IRealityETH realityEth = IRealityETH(reality);
        openingTS = realityEth.getOpeningTS(questionId);
        timeout = realityEth.getTimeout(questionId);
        bounty = realityEth.getBounty(questionId);
        bond = realityEth.getBond(questionId);

        // Return Reality info about received market id
        return (questionId, openingTS, timeout, bounty, bond);
    }

    /**
     * @notice Get information about a Question resolution status
	 * @param marketId The Market Id  to get Reality result info
	 * @return questionId question identifier
	 * @return answer the current last or final answer value (as bytes32 index)
	 * @return finalizeTS The pending time to reach the answer timeout
	 * @return lastHash The history hash of the last answer
	 * @return isFinalized Whether the question is finalized
	 * @return isPendingArbitration Whether the question is pending arbitration
	 */
    function getRealityResultInfo(uint256 marketId) external view returns (
        bytes32 questionId,
        bytes32 answer,
        uint32 finalizeTS,
        bytes32 lastHash,
        bool isFinalized,
        bool isPendingArbitration
    ) {
        // Get Reality question id for received market
        questionId = markets[marketId].questionId;

        // Validate existence of received market
        require(questionId != bytes32(0), "Market Id not found");

        IRealityETH realityEth = IRealityETH(reality);
        answer = realityEth.getBestAnswer(questionId);
        finalizeTS = realityEth.getFinalizeTS(questionId);
        lastHash = realityEth.getHistoryHash(questionId);
        isFinalized = realityEth.isFinalized(questionId);
        isPendingArbitration = realityEth.isPendingArbitration(questionId);

        return (questionId, answer, finalizeTS, lastHash, isFinalized, isPendingArbitration);
    }

    /**
     * @notice Internal helper function that formats a question string according to Reality.eth specifications
	 * @dev Combines question text, outcomes, and category using the Reality.eth separator '␟'
	 * @param question The main question text to be asked
	 * @param outcomes Array of possible answer options that will be presented to users
	 * @param category The classification category for the question
	 * @return formatedQuestion A output string in the format: "question␟['outcome1','outcome2',...]␟category␟"
	 */
    function _formatQuestion(
        string calldata question,
        string[] calldata outcomes,
        string calldata category
    ) internal pure returns (string memory formatedQuestion) {
        // Build outcome CSV string
        bytes memory outcomesBytes = bytes("");
        if (outcomes.length > 0) {
            outcomesBytes = abi.encodePacked('"', outcomes[0], '"');
            for (uint256 i = 1; i < outcomes.length; i++) {
                outcomesBytes = abi.encodePacked(outcomesBytes, ',"', outcomes[i], '"');
            }
        }
        // Build question string based on Reality custom format
        formatedQuestion = string(
            abi.encodePacked(question, unicode"␟", string(outcomesBytes), unicode"␟", category, unicode"␟")
        );
        return formatedQuestion;
    }

    /**
     * @notice Converts an array of strings into a comma-separated string
	 * @dev Example: ["Yes", "No", "Maybe"] => "Yes,No,Maybe"
	 * @param array The array of strings to join
	 * @return A single string with all elements joined by commas, or empty string if array is empty
	 */
    function _arrayToCSV(string[] memory array) internal pure returns (string memory) {
        if (array.length == 0) {
            return "";
        }

        bytes memory csvBytes = bytes(array[0]);
        for (uint i = 1; i < array.length; i++) {
            csvBytes = abi.encodePacked(csvBytes, ",", array[i]);
        }
        return string(csvBytes);
    }

    /**
     * @notice Splits a comma-separated string into an array of individual strings
	 * @dev Example: "Yes,No,Maybe" => ["Yes", "No", "Maybe"]
	 * @param csv The comma-separated string to split
	 * @return An array of individual strings, or empty array if input is empty
	 */
    function _csvToArray(string memory csv) internal pure returns (string[] memory) {
        bytes memory csvBytes = bytes(csv);
        if (csvBytes.length == 0) {
            return new string[](0);
        }

        // 1. Count how many elements we have
        uint256 count = 1;
        for (uint256 i = 0; i < csvBytes.length; i++) {
            if (csvBytes[i] == ",") {
                count++;
            }
        }

        // 2. Create the array and populate it
        string[] memory result = new string[](count);
        uint256 resultIndex = 0;
        uint256 startIndex = 0;

        for (uint256 i = 0; i < csvBytes.length; i++) {
            if (csvBytes[i] == ",") {
                result[resultIndex] = _substring(csvBytes, startIndex, i);
                resultIndex++;
                startIndex = i + 1;
            }
        }

        // Add the last element
        result[resultIndex] = _substring(csvBytes, startIndex, csvBytes.length);

        return result;
    }

    /**
     * @notice Extracts a portion of a bytes array into a new string
	 * @dev Helper function for _csvToArray to extract individual elements
	 * @param source The source bytes array to extract from
	 * @param start The starting index (inclusive) in the source array
	 * @param end The ending index (exclusive) in the source array
	 * @return A new string containing the extracted bytes
	 */
    function _substring(bytes memory source, uint256 start, uint256 end) internal pure returns (string memory) {
        uint256 len = end - start;
        bytes memory dest = new bytes(len);
        for (uint256 i = 0; i < len; i++) {
            dest[i] = source[start + i];
        }
        return string(dest);
    }

    /**
     * @notice Accept ETH for from any Transfer, Send or Call with value
	 */
    receive() external payable {}

    // Whitelisted functions: Only admin
    function setPrecogMaster(address master) external onlyAdmin {
        precogMaster = master;
    }

    function setReality(address realityProxy) external onlyAdmin {
        reality = realityProxy;
    }

    function setArbitrator(address arbitratorProxy) external onlyAdmin {
        arbitrator = arbitratorProxy;
    }

    function setMaxAnswerBond(uint256 maxBond) external onlyAdmin {
        maxAnswerBond = maxBond;
    }

    function unregisterMarket(uint256 id, address market) external onlyAdmin {
        require(markets[id].market == market, "Invalid market");
        delete markets[id];
    }

    function addMarketReporter(
        uint256 marketId,
        address account
    ) external onlyAdmin {
        // Verify that the account is not already registered (to avoid reset 'submitted' flag)
        require(!marketReporters[marketId][account], "Invalid reporter");

        // Register account as reporter for the received market id
        marketReporters[marketId][account] = true;
    }

    function removeMarketReporter(
        uint256 marketId,
        address account
    ) external onlyAdmin {
        // Verify that the account is already registered as reporter
        require(marketReporters[marketId][account], "Invalid reporter");

        // Disable account as allowed reporter for the received market id
        marketReporters[marketId][account] = false;
    }

    function addReporter(address account) external onlyAdmin {
        grantRole(REPORTER_ROLE, account);
    }

    function removeReporter(address account) external onlyAdmin {
        revokeRole(REPORTER_ROLE, account);
    }

    function addAdmin(address account) external onlyAdmin {
        grantRole(ADMIN_ROLE, account);
    }

    function removeAdmin(address account) external onlyAdmin {
        revokeRole(ADMIN_ROLE, account);
    }

    function withdraw(address _token) public onlyAdmin {
        if (_token == address(0)) {
            payable(msg.sender).transfer(address(this).balance);
        } else {
            IERC20(_token).safeTransfer(
                msg.sender,
                IERC20(_token).balanceOf(address(this))
            );
        }
    }
}

